            <input type="number" placeholder="Prize Pool" className="flex-1 px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.prizePool} onChange={e => setFormData({ ...formData, prizePool: parseFloat(e.target.value) })} required />
