          <input type="text" placeholder="Thumbnail URL" className="w-full px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.thumbnail} onChange={e => setFormData({ ...formData, thumbnail: e.target.value })} />
          <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg">SAVE TOURNAMENT</button>
        </form>
      )}

      <div className="space-y-4">
        {tournaments.map(t => (
          <div key={t.id} className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-start mb-4">
              <div className="flex items-center">
                <div className="w-12 h-12 rounded-2xl bg-gray-100 mr-3 overflow-hidden">
                  <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/100`} className="w-full h-full object-cover" />
                </div>
                <div>
                  <h4 className="font-bold text-gray-800 text-sm">{t.title}</h4>
                  <p className="text-[10px] text-gray-400 font-bold uppercase">{t.game} • ₹{t.entryFee} Entry</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <div className="text-[10px] font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-lg">
                  <i className="fas fa-users mr-1"></i>
                  {Object.keys(t.participants || {}).length}
                </div>
                <div className={`px-2 py-1 rounded-lg text-[10px] font-bold ${t.status === 'Live' ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'}`}>
                  {t.status}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 mt-4">
              <button onClick={() => updateStatus(t.id, 'Live')} className="text-[10px] font-bold py-2 bg-red-600 text-white rounded-lg">SET LIVE</button>
              <button onClick={() => updateStatus(t.id, 'Completed')} className="text-[10px] font-bold py-2 bg-gray-800 text-white rounded-lg">COMPLETE</button>
              <button onClick={() => handleDelete(t.id)} className="text-[10px] font-bold py-2 bg-red-100 text-red-600 rounded-lg">DELETE</button>
              <button className="text-[10px] font-bold py-2 bg-indigo-100 text-indigo-600 rounded-lg">MANAGE PLAYERS</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

