      } else {
        setTournaments([]);
      }
    };
    tourRef.on('value', handleValue);
    return () => tourRef.off('value', handleValue);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editing) {
        // Fix: Use ref.update() for editing
        await db.ref(`tournaments/${editing.id}`).update(formData);
        setEditing(null);
      } else {
        // Fix: Use ref.push() and push.set() for creation
        const newRef = db.ref('tournaments').push();
        await newRef.set({
          ...formData,
          status: 'Upcoming',
          participants: {}
        });
      }
      setShowForm(false);
      setFormData({ title: '', game: 'Free Fire', entryFee: 0, prizePool: 0, matchTime: '', thumbnail: '', commission: 10 });
    } catch (err: any) { alert(err.message); }
  };

  const updateStatus = async (tid: string, status: string) => {
    try {
      const updates: any = { status };

      if (status === 'Live') {
        updates.roomId = window.prompt("Enter Room ID:") || "";
        updates.roomPassword = window.prompt("Enter Room Password:") || "";
      } else if (status === 'Completed') {
        const winnerUid = window.prompt("Enter Winner User ID (UID):");
        if (!winnerUid) return;

        // Fetch tournament for prize details
        const tSnap = await db.ref(`tournaments/${tid}`).once('value');
        const tournament = tSnap.val();

        updates.winnerUid = winnerUid;

        // Credit prize pool to winner's wallet
        const userSnap = await db.ref(`users/${winnerUid}`).once('value');
        if (userSnap.exists()) {
          const userData = userSnap.val();
          const currentBalance = userData.wallet || 0;
          const prize = tournament.prizePool || 0;

          const batchUpdates: any = {};
          batchUpdates[`users/${winnerUid}/wallet`] = currentBalance + prize;

          // Add transaction record
          const txnRef = db.ref(`users/${winnerUid}/transactions`).push();
          batchUpdates[`users/${winnerUid}/transactions/${txnRef.key}`] = {
            amount: prize,
            type: 'credit',
            description: `Winner Prize: ${tournament.title}`,
            timestamp: Date.now()
          };

          await db.ref().update(batchUpdates);
        } else {
          alert("Winner UID not found in database. Status updated but prize not credited.");
        }
      }

      // Update tournament status
      await db.ref(`tournaments/${tid}`).update(updates);
      alert(`Tournament marked as ${status}`);
    } catch (err: any) {
      alert("Error updating tournament: " + err.message);
    }
  };

  const handleDelete = async (tid: string) => {
    if (window.confirm("Delete this tournament?")) {
      // Fix: Use ref.remove()
      await db.ref(`tournaments/${tid}`).remove();
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">Tournaments</h2>
        <button onClick={() => setShowForm(!showForm)} className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-md">
          {showForm ? 'CLOSE' : 'CREATE NEW'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-lg border border-gray-100 space-y-4 animate-in slide-in-from-top duration-300">
          <input type="text" placeholder="Tournament Title" className="w-full px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} required />
          <select className="w-full px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.game} onChange={e => setFormData({ ...formData, game: e.target.value })}>
            <option>Free Fire</option>
            <option>BGMI</option>
            <option>CODM</option>
            <option>Valorant Mobile</option>
          </select>
          <div className="flex gap-4">
            <input type="number" placeholder="Entry Fee" className="flex-1 px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.entryFee} onChange={e => setFormData({ ...formData, entryFee: parseFloat(e.target.value) })} required />
            <input type="number" placeholder="Prize Pool" className="flex-1 px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.prizePool} onChange={e => setFormData({ ...formData, prizePool: parseFloat(e.target.value) })} required />
          </div>
          <input type="datetime-local" className="w-full px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.matchTime} onChange={e => setFormData({ ...formData, matchTime: e.target.value })} required />
          <input type="text" placeholder="Thumbnail URL" className="w-full px-4 py-3 bg-gray-50 rounded-xl border border-gray-200" value={formData.thumbnail} onChange={e => setFormData({ ...formData, thumbnail: e.target.value })} />
          <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg">SAVE TOURNAMENT</button>
        </form>
      )}

      <div className="space-y-4">
        {tournaments.map(t => {
          const participantCount = Object.keys(t.participants || {}).length;
          const totalCollections = participantCount * t.entryFee;
          const calculatedCommission = totalCollections - t.prizePool;

          return (
            <div key={t.id} className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100">
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center">
                  <div className="w-12 h-12 rounded-2xl bg-gray-100 mr-3 overflow-hidden">
                    <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/100`} className="w-full h-full object-cover" alt="" />
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800 text-sm">{t.title}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{t.game} • ₹{t.entryFee} Entry</p>
                  </div>
                </div>
                <div className="flex flex-col items-end gap-1">
                   <div className="flex items-center gap-2">
                    <div className="text-[10px] font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-lg">
                      <i className="fas fa-users mr-1"></i>
                      {participantCount}
                    </div>
                    <div className={`px-2 py-1 rounded-lg text-[10px] font-bold ${t.status === 'Live' ? 'bg-red-50 text-red-600' : t.status === 'Completed' ? 'bg-gray-100 text-gray-600' : 'bg-blue-50 text-blue-600'}`}>
                      {t.status}
                    </div>
                  </div>
                  <div className={`text-[10px] font-bold px-2 py-1 rounded-lg ${calculatedCommission >= 0 ? 'bg-green-50 text-green-600' : 'bg-orange-50 text-orange-600'}`}>
                    Comm: ₹{calculatedCommission.toFixed(2)}
                  </div>
                </div>
              </div>

              {t.winnerUid && (
                <div className="bg-green-50 p-2 rounded-xl mb-3 flex items-center justify-between border border-green-100">
                  <span className="text-[9px] font-bold text-green-700">WINNER UID:</span>
                  <span className="text-[9px] font-mono text-green-800 font-bold select-all">{t.winnerUid}</span>
                </div>
              )}

              <div className="grid grid-cols-2 gap-2 mt-4">
                <button 
                  onClick={() => updateStatus(t.id, 'Live')} 
                  disabled={t.status === 'Completed'}
                  className="text-[10px] font-bold py-2 bg-red-600 text-white rounded-lg disabled:opacity-30"
                >
                  SET LIVE
                </button>
                <button 
                  onClick={() => updateStatus(t.id, 'Completed')} 
                  disabled={t.status === 'Completed'}
                  className="text-[10px] font-bold py-2 bg-gray-800 text-white rounded-lg disabled:opacity-30"
                >
                  {t.status === 'Completed' ? 'COMPLETED' : 'END & PAY'}
                </button>
                <button onClick={() => handleDelete(t.id)} className="text-[10px] font-bold py-2 bg-red-100 text-red-600 rounded-lg">DELETE</button>
                <button className="text-[10px] font-bold py-2 bg-indigo-100 text-indigo-600 rounded-lg">MANAGE PLAYERS</button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

