        {isLogin ? 'Sign in to access your dashboard' : 'Create an account to start winning'}
      </p>

      <div className="flex w-full bg-gray-100 rounded-xl p-1 mb-8">
        <button 
          onClick={() => setIsLogin(true)}
          className={`flex-1 py-2 rounded-lg text-sm font-semibold transition-all ${isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}
        >
          Login
        </button>
        <button 
          onClick={() => setIsLogin(false)}
          className={`flex-1 py-2 rounded-lg text-sm font-semibold transition-all ${!isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}
        >
          Sign Up
        </button>
      </div>

      <form onSubmit={handleSubmit} className="w-full space-y-4">
        {error && (
          <div className="bg-red-50 text-red-600 text-xs p-3 rounded-lg border border-red-100 flex items-start">
            <i className="fas fa-exclamation-circle mt-0.5 mr-2"></i>
            <span>{error}</span>
          </div>
