        {msg && (
          <div className="bg-green-50 text-green-600 text-xs p-3 rounded-lg border border-green-100 flex items-start">
            <i className="fas fa-check-circle mt-0.5 mr-2"></i>
            <span>{msg}</span>
          </div>
        )}

        {!isLogin && (
          <div>
            <label className="text-xs font-bold text-gray-600 uppercase mb-1 block">Username</label>
            <div className="relative">
              <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
              <input 
                type="text" 
                required 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
