import React, { useState, useEffect } from 'react';
import { auth, db } from '../../firebase';
import { Tournament, UserData } from '../../types';

const UserHome: React.FC = () => {
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [loading, setLoading] = useState(true);
  const [joining, setJoining] = useState<string | null>(null);

  useEffect(() => {
    const tournamentsRef = db.ref('tournaments');
    const handleValue = (snapshot: any) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.keys(data).map(key => ({
          ...data[key],
          id: key
        })).filter(t => t.status !== 'Completed');
        setTournaments(list);
      } else {
        setTournaments([]);
      }
      setLoading(false);
    };
    tournamentsRef.on('value', handleValue);
    return () => tournamentsRef.off('value', handleValue);
  }, []);

  const handleJoin = async (tournament: Tournament) => {
    const user = auth.currentUser;
    if (!user) return;

    if (joining) return;

    try {
      if (tournament.participants && tournament.participants[user.uid]) {
        alert("You have already joined this tournament.");
        return;
      }

      const userRef = db.ref(`users/${user.uid}`);
      const userSnap = await userRef.once('value');
      const userData: UserData = userSnap.val();

      if (userData.wallet < tournament.entryFee) {
        alert("Insufficient balance! Please add money to your wallet.");
        return;
      }

      // Step 1: Collect Game UID
      const gameUid = window.prompt("Enter your Free Fire UID (10-12 digits):");
      if (!gameUid) return;
      if (!/^\d{10,12}$/.test(gameUid)) {
        alert("Invalid UID! Must be 10-12 digits.");
        return;
      }

      // Step 2: Collect Game Username (IGN)
      const gameUsername = window.prompt("Enter your In-Game Name (IGN):");
      if (!gameUsername) return;

      if (!window.confirm(`Join ${tournament.title} for ₹${tournament.entryFee}?\nDetails: ${gameUsername} (${gameUid})`)) {
        return;
      }

      setJoining(tournament.id);

      const newWalletBalance = userData.wallet - tournament.entryFee;

      const updates: any = {};
      updates[`users/${user.uid}/wallet`] = newWalletBalance;
      updates[`tournaments/${tournament.id}/participants/${user.uid}`] = {
        username: userData.username,
        gameUid: gameUid,
        gameUsername: gameUsername,
        result: 'Participated'
      };

      const txnRef = db.ref(`users/${user.uid}/transactions`).push();
      updates[`users/${user.uid}/transactions/${txnRef.key}`] = {
        amount: tournament.entryFee,
        type: 'debit',
        description: `Joined Tournament: ${tournament.title}`,
        timestamp: Date.now()
      };

      await db.ref().update(updates);
      alert("Successfully joined tournament!");

    } catch (err: any) {
      alert("Error: " + err.message);
    } finally {
      setJoining(null);
    }
  };

  if (loading) {
    return <div className="flex justify-center py-10"><i className="fas fa-spinner animate-spin text-3xl text-blue-500"></i></div>;
  }

  return (
    <div className="space-y-6">
      <div className="bg-gradient-to-br from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg overflow-hidden relative">
        <div className="relative z-10">
          <h2 className="text-2xl font-bold mb-1">Weekly Battle Royale</h2>
          <p className="text-white/80 text-sm mb-4">Total prize pool worth ₹10,000</p>
          <button className="bg-white text-indigo-600 px-5 py-2 rounded-xl font-bold text-sm shadow-md active:scale-95 transition-all">
            VIEW DETAILS
          </button>
        </div>
        <i className="fas fa-gamepad absolute -bottom-4 -right-4 text-8xl text-white/10 rotate-12"></i>
      </div>

      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold text-gray-800">Available Tournaments</h3>
        <span className="text-xs font-semibold text-blue-600">{tournaments.length} Matches</span>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {tournaments.length === 0 ? (
          <div className="text-center py-20">
            <p className="text-gray-500">No upcoming matches at the moment.</p>
          </div>
        ) : (
          tournaments.map((t) => (
            <div key={t.id} className="bg-white rounded-2xl overflow-hidden shadow-md border border-gray-100">
              <div className="relative h-40 w-full overflow-hidden">
                <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/400/200`} className="w-full h-full object-cover" />
                <div className="absolute top-3 left-3 bg-black/60 backdrop-blur-md text-white text-[10px] px-2 py-1 rounded-lg font-bold uppercase">
                  {t.game}
                </div>
              </div>
              <div className="p-4">
                <h4 className="font-bold text-lg mb-2">{t.title}</h4>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  <div>
                    <p className="text-[10px] text-gray-400 uppercase font-bold">Prize</p>
                    <p className="text-xs font-bold text-gray-800">₹{t.prizePool}</p>
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-400 uppercase font-bold">Entry</p>
                    <p className="text-xs font-bold text-gray-800">₹{t.entryFee}</p>
                  </div>
                </div>
                <button 
                  onClick={() => handleJoin(t)}
                  disabled={joining === t.id}
                  className="w-full bg-blue-600 text-white py-2 rounded-xl text-sm font-bold shadow-md active:scale-95 disabled:opacity-50"
                >
                  {joining === t.id ? 'JOINING...' : (t.participants?.[auth.currentUser?.uid || ''] ? 'JOINED' : 'JOIN NOW')}
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default UserHome;

