import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { Tournament } from '../../types';

const AdminManageTournaments: React.FC = () => {
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [viewPlayers, setViewPlayers] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    title: '',
    game: 'Free Fire',
    entryFee: 0,
    prizePool: 0,
    matchTime: '',
    thumbnail: '',
    commission: 10
  });

  useEffect(() => {
    const tourRef = db.ref('tournaments');
    const handleValue = (snapshot: any) => {
      const data = snapshot.val();
      if (data) {
        setTournaments(Object.keys(data).map(key => ({ ...data[key], id: key })));
      } else {
        setTournaments([]);
      }
    };
    tourRef.on('value', handleValue);
    return () => tourRef.off('value', handleValue);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const newRef = db.ref('tournaments').push();
      await newRef.set({
        ...formData,
        status: 'Upcoming',
        participants: {}
      });
      setShowForm(false);
      setFormData({ title: '', game: 'Free Fire', entryFee: 0, prizePool: 0, matchTime: '', thumbnail: '', commission: 10 });
    } catch (err: any) { alert(err.message); }
  };

  const updateStatus = async (tid: string, status: string) => {
    try {
      const updates: any = { status };
      if (status === 'Live') {
        updates.roomId = window.prompt("Enter Room ID:") || "";
        updates.roomPassword = window.prompt("Enter Room Password:") || "";
      } else if (status === 'Completed') {
        const winnerUid = window.prompt("Enter Winner User ID (UID from player list):");
        if (!winnerUid) return;
        const tSnap = await db.ref(`tournaments/${tid}`).once('value');
        const tournament = tSnap.val();
        updates.winnerUid = winnerUid;
        const userSnap = await db.ref(`users/${winnerUid}`).once('value');
        if (userSnap.exists()) {
          const userData = userSnap.val();
          const currentBalance = userData.wallet || 0;
          const prize = tournament.prizePool || 0;
          const batchUpdates: any = {};
          batchUpdates[`users/${winnerUid}/wallet`] = currentBalance + prize;
          const txnRef = db.ref(`users/${winnerUid}/transactions`).push();
          batchUpdates[`users/${winnerUid}/transactions/${txnRef.key}`] = {
            amount: prize,
            type: 'credit',
            description: `Winner Prize: ${tournament.title}`,
            timestamp: Date.now()
          };
          await db.ref().update(batchUpdates);
        } else {
          alert("Winner UID not found!");
        }
      }
      await db.ref(`tournaments/${tid}`).update(updates);
    } catch (err: any) { alert(err.message); }
  };

  const handleDelete = async (tid: string) => {
    if (window.confirm("Delete this tournament?")) {
      await db.ref(`tournaments/${tid}`).remove();
    }
  };

  const selectedTourneyPlayers = viewPlayers ? tournaments.find(t => t.id === viewPlayers) : null;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">Tournaments</h2>
        <button onClick={() => setShowForm(!showForm)} className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-md">
          {showForm ? 'CLOSE' : 'CREATE NEW'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-lg border border-gray-100 space-y-4">
          <input type="text" placeholder="Tournament Title" className="w-full px-4 py-3 bg-gray-50 rounded-xl border" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} required />
          <div className="flex gap-4">
            <input type="number" placeholder="Entry Fee" className="flex-1 px-4 py-3 bg-gray-50 rounded-xl border" value={formData.entryFee} onChange={e => setFormData({ ...formData, entryFee: parseFloat(e.target.value) })} required />
            <input type="number" placeholder="Prize Pool" className="flex-1 px-4 py-3 bg-gray-50 rounded-xl border" value={formData.prizePool} onChange={e => setFormData({ ...formData, prizePool: parseFloat(e.target.value) })} required />
          </div>
          <input type="datetime-local" className="w-full px-4 py-3 bg-gray-50 rounded-xl border" value={formData.matchTime} onChange={e => setFormData({ ...formData, matchTime: e.target.value })} required />
          <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold">SAVE TOURNAMENT</button>
        </form>
      )}

      {viewPlayers && selectedTourneyPlayers && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl p-6 relative max-h-[80vh] overflow-y-auto">
             <button onClick={() => setViewPlayers(null)} className="absolute top-4 right-4 text-gray-400"><i className="fas fa-times"></i></button>
             <h3 className="text-lg font-black mb-4 uppercase">Players: {selectedTourneyPlayers.title}</h3>
             <div className="space-y-3">
                {Object.keys(selectedTourneyPlayers.participants || {}).length === 0 ? <p className="text-gray-400 text-center py-10">No players joined yet.</p> : 
                 Object.entries(selectedTourneyPlayers.participants || {}).map(([uid, data]: [string, any]) => (
                   <div key={uid} className="bg-gray-50 p-4 rounded-2xl border border-gray-100">
                      <div className="flex justify-between items-start">
                         <div>
                            <p className="text-xs font-black text-gray-900">{data.gameUsername}</p>
                            <p className="text-[10px] text-blue-600 font-bold">UID: {data.gameUid}</p>
                         </div>
                         <div className="text-right">
                            <p className="text-[9px] text-gray-400 uppercase font-bold">App UID</p>
                            <p className="text-[10px] font-mono text-gray-600 select-all">{uid}</p>
                         </div>
                      </div>
                   </div>
                 ))}
             </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {tournaments.map(t => {
          const participantCount = Object.keys(t.participants || {}).length;
          return (
            <div key={t.id} className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100">
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center">
                  <div className="w-12 h-12 rounded-2xl bg-gray-100 mr-3 overflow-hidden">
                    <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/100`} className="w-full h-full object-cover" />
                  </div>
                  <div>
                    <h4 className="font-bold text-gray-800 text-sm">{t.title}</h4>
                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{t.game}</p>
                  </div>
                </div>
                <div className="flex flex-col items-end gap-1">
                   <div className="flex items-center gap-2">
                    <div className="text-[10px] font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-lg">
                      <i className="fas fa-users mr-1"></i>
                      {participantCount}
                    </div>
                    <div className={`px-2 py-1 rounded-lg text-[10px] font-bold ${t.status === 'Live' ? 'bg-red-50 text-red-600' : t.status === 'Completed' ? 'bg-gray-100 text-gray-600' : 'bg-blue-50 text-blue-600'}`}>
                      {t.status}
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 mt-4">
                <button onClick={() => updateStatus(t.id, 'Live')} disabled={t.status === 'Completed'} className="text-[10px] font-bold py-2 bg-red-600 text-white rounded-lg disabled:opacity-30 uppercase tracking-widest">SET LIVE</button>
                <button onClick={() => updateStatus(t.id, 'Completed')} disabled={t.status === 'Completed'} className="text-[10px] font-bold py-2 bg-gray-800 text-white rounded-lg disabled:opacity-30 uppercase tracking-widest">END & PAY</button>
                <button onClick={() => setViewPlayers(t.id)} className="text-[10px] font-bold py-2 bg-indigo-100 text-indigo-600 rounded-lg uppercase tracking-widest">PLAYERS</button>
                <button onClick={() => handleDelete(t.id)} className="text-[10px] font-bold py-2 bg-red-100 text-red-600 rounded-lg uppercase tracking-widest">DELETE</button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

