import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { auth, db } from './firebase';
import { UserData } from './types';
import firebase from 'firebase/compat/app';

// Layouts & Pages
import UserLayout from './components/UserLayout';
import AdminLayout from './components/AdminLayout';
import LoginPage from './pages/LoginPage';
import UserHome from './pages/user/UserHome';
import UserMyMatches from './pages/user/UserMyMatches';
import UserWallet from './pages/user/UserWallet';
import UserProfile from './pages/user/UserProfile';
import UserSupport from './pages/user/UserSupport';
import AdminDashboard from './pages/admin/AdminDashboard';
import AdminManageTournaments from './pages/admin/AdminManageTournaments';
import AdminRequests from './pages/admin/AdminRequests';
import AdminSettings from './pages/admin/AdminSettings';
import AdminTickets from './pages/admin/AdminTickets';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [userData, setUserData] = useState<UserData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const userRef = db.ref(`users/${currentUser.uid}`);
        const handleValue = (snapshot: any) => {
          const data = snapshot.val();
          if (data) {
            setUserData({ ...data, uid: currentUser.uid });
          }
          setLoading(false);
        };
        userRef.on('value', handleValue);
        return () => userRef.off('value', handleValue);
      } else {
        setUserData(null);
        setLoading(false);
      }
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900 text-white">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        <Route 
          path="/login" 
          element={!user ? <LoginPage /> : <Navigate to="/" />} 
        />

        <Route 
          path="/" 
          element={user && userData?.role === 'user' ? <UserLayout /> : (user && userData?.role === 'admin' ? <Navigate to="/admin" /> : <Navigate to="/login" />)}
        >
          <Route index element={<UserHome />} />
          <Route path="home" element={<UserHome />} />
          <Route path="matches" element={<UserMyMatches />} />
          <Route path="wallet" element={<UserWallet />} />
          <Route path="profile" element={<UserProfile />} />
          <Route path="support" element={<UserSupport />} />
        </Route>

        <Route 
          path="/admin" 
          element={user && userData?.role === 'admin' ? <AdminLayout /> : <Navigate to="/login" />}
        >
          <Route index element={<AdminDashboard />} />
          <Route path="dashboard" element={<AdminDashboard />} />
          <Route path="tournaments" element={<AdminManageTournaments />} />
          <Route path="requests" element={<AdminRequests />} />
          <Route path="tickets" element={<AdminTickets />} />
          <Route path="settings" element={<AdminSettings />} />
        </Route>

        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { auth, db } from '../../firebase';
import { Ticket, ChatMessage, UserData } from '../../types';

const UserSupport: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [text, setText] = useState('');
  const [ticketId, setTicketId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const user = auth.currentUser;
    if (!user) return;

    // Check for an open ticket for this user
    const ticketsRef = db.ref('tickets');
    const query = ticketsRef.orderByChild('uid').equalTo(user.uid);

    const handleValue = (snapshot: any) => {
      const data = snapshot.val();
      if (data) {
        // Find the most recent open ticket or any ticket
        const tickets = Object.keys(data).map(key => ({ ...data[key], id: key }));
        const openTicket = tickets.find(t => t.status === 'open') || tickets[0];
        setTicketId(openTicket.id);

        if (openTicket.messages) {
          const msgList = Object.values(openTicket.messages) as ChatMessage[];
          setMessages(msgList.sort((a, b) => a.timestamp - b.timestamp));
        }
      }
      setLoading(false);
    };

    query.on('value', handleValue);
    return () => query.off('value', handleValue);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!text.trim()) return;

    const user = auth.currentUser;
    if (!user) return;

    try {
      let currentTicketId = ticketId;

      // If no ticket exists, create one
      if (!currentTicketId) {
        const userSnap = await db.ref(`users/${user.uid}`).once('value');
        const userData: UserData = userSnap.val();

        const newTicketRef = db.ref('tickets').push();
        currentTicketId = newTicketRef.key;
        await newTicketRef.set({
          uid: user.uid,
          username: userData.username,
          appId: userData.appId,
          status: 'open',
          lastUpdate: Date.now(),
          lastMessage: text.trim()
        });
        setTicketId(currentTicketId);
      }

      const msgRef = db.ref(`tickets/${currentTicketId}/messages`).push();
      const newMsg: ChatMessage = {
        senderId: user.uid,
        senderName: 'You',
        role: 'user',
        text: text.trim(),
        timestamp: Date.now()
      };

      await msgRef.set(newMsg);
      await db.ref(`tickets/${currentTicketId}`).update({
        lastUpdate: Date.now(),
        lastMessage: text.trim(),
        status: 'open' // Reopen if it was resolved
      });

      setText('');
    } catch (err: any) {
      alert(err.message);
    }
  };

  if (loading) return <div className="flex justify-center py-20"><i className="fas fa-spinner animate-spin text-2xl text-blue-500"></i></div>;

  return (
    <div className="flex flex-col h-[calc(100vh-180px)] bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="bg-blue-600 p-4 text-white flex justify-between items-center">
        <div>
          <h3 className="font-bold text-sm uppercase tracking-wider">Support Chat</h3>
          <p className="text-[10px] opacity-70">Average response time: 15 mins</p>
        </div>
        <i className="fas fa-headset text-xl opacity-50"></i>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
        {messages.length === 0 ? (
          <div className="text-center py-10">
            <div className="w-16 h-16 bg-blue-50 text-blue-400 rounded-full flex items-center justify-center mx-auto mb-4">
              <i className="fas fa-comments text-2xl"></i>
            </div>
            <p className="text-gray-500 text-sm font-medium">Hello! How can we help you today?</p>
            <p className="text-[10px] text-gray-400 mt-1 uppercase font-bold">Type your message below to start</p>
          </div>
        ) : (
          messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl text-sm shadow-sm ${
                msg.role === 'user' 
                ? 'bg-blue-600 text-white rounded-tr-none' 
                : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
              }`}>
                <p className="font-medium">{msg.text}</p>
                <p className={`text-[8px] mt-1 text-right ${msg.role === 'user' ? 'text-white/50' : 'text-gray-400'}`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
            </div>
          ))
        )}
        <div ref={chatEndRef} />
      </div>

      <form onSubmit={sendMessage} className="p-3 bg-white border-t border-gray-100 flex gap-2">
        <input 
          type="text" 
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Type your message..."
          className="flex-1 bg-gray-50 border-none rounded-2xl px-4 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
        />
        <button type="submit" className="w-10 h-10 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-transform">
          <i className="fas fa-paper-plane"></i>
        </button>
      </form>
    </div>
  );
};

export default UserSupport;

import React, { useState, useEffect, useRef } from 'react';
import { db, auth } from '../../firebase';
import { Ticket, ChatMessage } from '../../types';

const AdminTickets: React.FC = () => {
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [replyText, setReplyText] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ticketsRef = db.ref('tickets');
    const handleValue = (snapshot: any) => {
      const data = snapshot.val();
      if (data) {
        setTickets(Object.keys(data).map(key => ({ ...data[key], id: key }))
          .sort((a, b) => b.lastUpdate - a.lastUpdate));
      }
    };
    ticketsRef.on('value', handleValue);
    return () => ticketsRef.off('value', handleValue);
  }, []);

  useEffect(() => {
    if (selectedTicketId) {
      const msgsRef = db.ref(`tickets/${selectedTicketId}/messages`);
      const handleMsgs = (snapshot: any) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.values(data) as ChatMessage[];
          setMessages(list.sort((a, b) => a.timestamp - b.timestamp));
        } else {
          setMessages([]);
        }
      };
      msgsRef.on('value', handleMsgs);
      return () => msgsRef.off('value', handleMsgs);
    }
  }, [selectedTicketId]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendReply = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!replyText.trim() || !selectedTicketId) return;

    try {
      const msgRef = db.ref(`tickets/${selectedTicketId}/messages`).push();
      const newMsg: ChatMessage = {
        senderId: 'admin',
        senderName: 'Admin Support',
        role: 'admin',
        text: replyText.trim(),
        timestamp: Date.now()
      };

      await msgRef.set(newMsg);
      await db.ref(`tickets/${selectedTicketId}`).update({
        lastUpdate: Date.now(),
        lastMessage: replyText.trim()
      });
      setReplyText('');
    } catch (err: any) { alert(err.message); }
  };

  const closeTicket = async () => {
    if (selectedTicketId && window.confirm("Close this ticket?")) {
      await db.ref(`tickets/${selectedTicketId}`).update({ status: 'resolved' });
      setSelectedTicketId(null);
    }
  };

  const selectedTicket = tickets.find(t => t.id === selectedTicketId);

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] gap-4">
      {!selectedTicketId ? (
        <div className="space-y-4">
          <h2 className="text-xl font-bold text-gray-800">Support Center</h2>
          {tickets.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
               <p className="text-gray-400">No support tickets found.</p>
            </div>
          ) : (
            tickets.map(t => (
              <button 
                key={t.id} 
                onClick={() => setSelectedTicketId(t.id)}
                className="w-full bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex justify-between items-center text-left"
              >
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-bold text-gray-800 text-sm truncate">{t.username}</span>
                    <span className="text-[9px] font-mono text-gray-400">#{t.appId}</span>
                  </div>
                  <p className="text-[10px] text-gray-500 truncate font-medium">{t.lastMessage}</p>
                </div>
                <div className="text-right flex flex-col items-end ml-4">
                  <span className={`text-[8px] font-bold px-2 py-0.5 rounded uppercase mb-1 ${t.status === 'open' ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                    {t.status}
                  </span>
                  <p className="text-[8px] text-gray-400 font-bold">{new Date(t.lastUpdate).toLocaleTimeString()}</p>
                </div>
              </button>
            ))
          )}
        </div>
      ) : (
        <div className="flex flex-col flex-1 bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden relative">
          <div className="bg-gray-900 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-3">
              <button onClick={() => setSelectedTicketId(null)} className="p-2"><i className="fas fa-arrow-left"></i></button>
              <div>
                <h3 className="font-bold text-sm uppercase">{selectedTicket?.username}</h3>
                <p className="text-[10px] text-gray-400">App ID: {selectedTicket?.appId}</p>
              </div>
            </div>
            <button onClick={closeTicket} className="text-[10px] font-bold bg-white/10 px-3 py-1.5 rounded-xl uppercase hover:bg-white/20">Resolve</button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/30">
            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'admin' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                  msg.role === 'admin' 
                  ? 'bg-indigo-600 text-white rounded-tr-none shadow-md shadow-indigo-100' 
                  : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
                }`}>
                  <p className="font-medium">{msg.text}</p>
                  <p className={`text-[8px] mt-1 text-right ${msg.role === 'admin' ? 'text-white/50' : 'text-gray-400'}`}>
                    {new Date(msg.timestamp).toLocaleTimeString()}
                  </p>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>

          <form onSubmit={sendReply} className="p-4 border-t flex gap-2">
            <input 
              type="text" 
              value={replyText}
              onChange={(e) => setReplyText(e.target.value)}
              placeholder="Type reply..."
              className="flex-1 bg-gray-50 border border-gray-200 rounded-2xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
            <button type="submit" className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center shadow-lg">
              <i className="fas fa-paper-plane"></i>
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default AdminTickets;

