import React, { useState, useEffect } from 'react';
// Fix: Removed modular database imports
import { db } from '../../firebase';
import { WalletRequest, UserData } from '../../types';

const AdminRequests: React.FC = () => {
  const [requests, setRequests] = useState<WalletRequest[]>([]);
  const [activeTab, setActiveTab] = useState<'deposit' | 'withdraw'>('deposit');

  useEffect(() => {
    // Fix: Use db.ref and ref.on for listeners
    const depRef = db.ref('addMoneyRequests');
    const handleDeposits = (snap: any) => {
      const data = snap.val();
      if (data) {
        const list = Object.keys(data).map(key => ({ ...data[key], id: key, type: 'deposit' as const }));
        setRequests(prev => [...prev.filter(r => r.type !== 'deposit'), ...list]);
      }
    };
    depRef.on('value', handleDeposits);

    const withRef = db.ref('withdrawRequests');
    const handleWithdraws = (snap: any) => {
      const data = snap.val();
      if (data) {
        const list = Object.keys(data).map(key => ({ ...data[key], id: key, type: 'withdraw' as const }));
        setRequests(prev => [...prev.filter(r => r.type !== 'withdraw'), ...list]);
      }
    };
    withRef.on('value', handleWithdraws);

    return () => {
      depRef.off('value', handleDeposits);
      withRef.off('value', handleWithdraws);
    };
  }, []);

  const handleAction = async (req: WalletRequest, status: 'approved' | 'rejected') => {
    if (!window.confirm(`${status.toUpperCase()} this request for ₹${req.amount}?`)) return;

    try {
      const updates: any = {};
      const path = req.type === 'deposit' ? 'addMoneyRequests' : 'withdrawRequests';
      updates[`${path}/${req.id}/status`] = status;

      if (status === 'approved') {
        const userRef = db.ref(`users/${req.uid}`);
        const userSnap = await userRef.once('value');
        const userData: UserData = userSnap.val();

        if (req.type === 'deposit') {
          updates[`users/${req.uid}/wallet_deposit`] = (userData.wallet_deposit || 0) + req.amount;
        } else {
          updates[`users/${req.uid}/wallet_winnings`] = (userData.wallet_winnings || 0) - req.amount;
        }

        const txnRef = db.ref(`users/${req.uid}/transactions`).push();
        updates[`users/${req.uid}/transactions/${txnRef.key}`] = {
          amount: req.amount,
          type: req.type === 'deposit' ? 'credit' : 'debit',
          description: req.type === 'deposit' ? 'Wallet Recharge' : 'Funds Redemption',
          timestamp: Date.now()
        };
      }

      await db.ref().update(updates);
      alert("Request updated successfully!");
    } catch (err: any) { alert(err.message); }
  };

  const filtered = requests.filter(r => r.type === activeTab && r.status === 'pending');

  return (
    <div className="space-y-6">
      <div className="flex bg-white rounded-2xl p-1 shadow-sm border border-gray-100">
        <button onClick={() => setActiveTab('deposit')} className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'deposit' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500'}`}>DEPOSITS</button>
        <button onClick={() => setActiveTab('withdraw')} className={`flex-1 py-3 rounded-xl text-xs font-bold transition-all ${activeTab === 'withdraw' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500'}`}>WITHDRAWS</button>
      </div>

      <div className="space-y-4">
        {filtered.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
            <p className="text-gray-400 text-sm">No pending {activeTab}s.</p>
          </div>
        ) : (
          filtered.map(req => (
            <div key={req.id} className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 animate-in fade-in duration-300">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-bold text-gray-800">{req.username}</h4>
                  <p className="text-xs text-gray-400">{new Date(req.createdAt).toLocaleString()}</p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-black text-indigo-600">₹{req.amount}</p>
                </div>
              </div>

              <div className="bg-gray-50 rounded-2xl p-3 mb-4 text-xs font-mono break-all text-gray-600">
                {req.type === 'deposit' ? `TXN ID: ${req.txnId}` : `UPI ID: ${req.upiId}`}
              </div>

              <div className="flex gap-3">
                <button onClick={() => handleAction(req, 'approved')} className="flex-1 py-3 bg-green-600 text-white rounded-xl text-xs font-bold shadow-md shadow-green-100">APPROVE</button>
                <button onClick={() => handleAction(req, 'rejected')} className="flex-1 py-3 bg-red-100 text-red-600 rounded-xl text-xs font-bold">REJECT</button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

