import React, { useState } from 'react';
import { auth, db } from '../firebase';
import { UserData } from '../types';

const LoginPage: React.FC = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [msg, setMsg] = useState('');

  const generateAppId = () => {
    return Math.floor(100000 + Math.random() * 900000).toString();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setMsg('');
    setLoading(true);

    try {
      if (isLogin) {
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        const user = userCredential.user;

        if (user) {
          const userSnap = await db.ref(`users/${user.uid}`).once('value');
          const userData: UserData = userSnap.val();

          // Auto-fix missing App ID for legacy users
          if (!userData.appId || userData.appId === "undefined") {
            const newId = generateAppId();
            await db.ref(`users/${user.uid}`).update({ appId: newId });
          }

          if (userData && userData.banUntil && userData.banUntil > Date.now()) {
            const banDate = new Date(userData.banUntil).toLocaleString();
            await auth.signOut();
            setError(`You are banned until ${banDate}. Reason: ${userData.banReason || 'Violation of terms.'}`);
            return;
          }
        }
      } else {
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        const user = userCredential.user;

        if (user) {
          const role = email.toLowerCase().includes('admin') ? 'admin' : 'user';
          const appId = generateAppId();

          await db.ref(`users/${user.uid}`).set({
            appId: appId,
            username: username,
            email: email,
            wallet_deposit: 0,
            wallet_winnings: 0,
            role: role,
            createdAt: Date.now()
          });
        }
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = async () => {
    if (!email) {
      setError('Please enter your email first');
      return;
    }
    try {
      await auth.sendPasswordResetEmail(email);
      setMsg('Password reset link sent to your email');
    } catch (err: any) {
      setError(err.message);
    }
  };

  return (
    <div className="min-h-screen max-w-md mx-auto bg-white flex flex-col items-center px-8 py-12">
      <div className="w-20 h-20 bg-gradient-to-tr from-blue-600 to-teal-400 rounded-3xl flex items-center justify-center shadow-lg mb-8">
        <i className="fas fa-gamepad text-white text-4xl"></i>
      </div>

      <h2 className="text-3xl font-extrabold text-gray-900 mb-2">
        {isLogin ? 'Welcome Back!' : 'Join the Arena'}
      </h2>
      <p className="text-gray-500 mb-8 text-center">
        {isLogin ? 'Sign in to access your account' : 'Create an account to start winning'}
      </p>

      <div className="flex w-full bg-gray-100 rounded-xl p-1 mb-8">
        <button 
          onClick={() => setIsLogin(true)}
          className={`flex-1 py-2 rounded-lg text-sm font-semibold transition-all ${isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}
        >
          Login
        </button>
        <button 
          onClick={() => setIsLogin(false)}
          className={`flex-1 py-2 rounded-lg text-sm font-semibold transition-all ${!isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}
        >
          Sign Up
        </button>
      </div>

      <form onSubmit={handleSubmit} className="w-full space-y-4">
        {error && (
          <div className="bg-red-50 text-red-600 text-xs p-3 rounded-lg border border-red-100 flex items-start">
            <i className="fas fa-exclamation-circle mt-0.5 mr-2"></i>
            <span>{error}</span>
          </div>
        )}
        {msg && (
          <div className="bg-green-50 text-green-600 text-xs p-3 rounded-lg border border-green-100 flex items-start">
            <i className="fas fa-check-circle mt-0.5 mr-2"></i>
            <span>{msg}</span>
          </div>
        )}

        {!isLogin && (
          <div>
            <label className="text-xs font-bold text-gray-600 uppercase mb-1 block">Username</label>
            <div className="relative">
              <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
              <input 
                type="text" 
                required 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="GamingNinja"
                className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all"
              />
            </div>
          </div>
        )}

        <div>
          <label className="text-xs font-bold text-gray-600 uppercase mb-1 block">Email Address</label>
          <div className="relative">
            <i className="fas fa-envelope absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="email" 
              required 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="name@example.com"
              className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all"
            />
          </div>
        </div>

        <div>
          <div className="flex justify-between items-center mb-1">
            <label className="text-xs font-bold text-gray-600 uppercase">Password</label>
            {isLogin && (
              <button type="button" onClick={handleReset} className="text-[10px] font-bold text-blue-600 uppercase hover:underline">
                Forgot?
              </button>
            )}
          </div>
          <div className="relative">
            <i className="fas fa-lock absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="password" 
              required 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="••••••••"
              className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all"
            />
          </div>
        </div>

        <button 
          type="submit" 
          disabled={loading}
          className="w-full py-4 bg-gradient-to-r from-blue-600 to-teal-500 text-white rounded-xl font-bold shadow-lg shadow-blue-200 active:scale-95 transition-transform disabled:opacity-50"
        >
          {loading ? (
            <i className="fas fa-circle-notch animate-spin"></i>
          ) : (
            isLogin ? 'SIGN IN' : 'CREATE ACCOUNT'
          )}
        </button>
      </form>

      <div className="mt-8 text-center text-sm text-gray-500">
        By continuing, you agree to our <span className="text-blue-600 font-semibold underline">Terms of Service</span>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { Tournament, UserData } from '../../types';

const AdminManageTournaments: React.FC = () => {
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [viewPlayers, setViewPlayers] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    title: '',
    game: 'Free Fire',
    entryFee: 0,
    prizePool: 0,
    matchTime: '',
    thumbnail: '',
  });

  useEffect(() => {
    const tourRef = db.ref('tournaments');
    const handleValue = (snapshot: any) => {
      const data = snapshot.val();
      if (data) {
        setTournaments(Object.keys(data).map(key => ({ ...data[key], id: key })));
      } else {
        setTournaments([]);
      }
    };
    tourRef.on('value', handleValue);
    return () => tourRef.off('value', handleValue);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const newRef = db.ref('tournaments').push();
      await newRef.set({
        ...formData,
        status: 'Upcoming',
        participants: {},
        createdAt: Date.now()
      });
      setShowForm(false);
      setFormData({ title: '', game: 'Free Fire', entryFee: 0, prizePool: 0, matchTime: '', thumbnail: '' });
      alert("Match created successfully!");
    } catch (err: any) { alert(err.message); }
  };

  const updateStatus = async (tid: string, status: string) => {
    try {
      const updates: any = { status };
      if (status === 'Live') {
        const roomId = window.prompt("Enter Room ID:");
        if (!roomId) return;
        updates.roomId = roomId;
        updates.roomPassword = window.prompt("Enter Room Password:") || "";
      } else if (status === 'Completed') {
        const winnerAppId = window.prompt("Enter Winner's 6-Digit App ID:");
        if (!winnerAppId || winnerAppId.length !== 6) {
          alert("Invalid App ID!");
          return;
        }

        // Find user by App ID
        const userQuery = await db.ref('users').orderByChild('appId').equalTo(winnerAppId).once('value');
        if (!userQuery.exists()) {
          alert("Winner App ID not found in database!");
          return;
        }

        const winnerUid = Object.keys(userQuery.val())[0];
        const userData: UserData = userQuery.val()[winnerUid];
        const tournament = tournaments.find(t => t.id === tid);

        if (!tournament) return;

        const batchUpdates: any = {};
        batchUpdates[`users/${winnerUid}/wallet_winnings`] = (userData.wallet_winnings || 0) + (tournament.prizePool || 0);
        batchUpdates[`tournaments/${tid}/status`] = 'Completed';
        batchUpdates[`tournaments/${tid}/winnerUid`] = winnerUid;

        const txnRef = db.ref(`users/${winnerUid}/transactions`).push();
        batchUpdates[`users/${winnerUid}/transactions/${txnRef.key}`] = {
          amount: tournament.prizePool,
          type: 'credit',
          description: `Tournament Prize: ${tournament.title}`,
          timestamp: Date.now()
        };

        await db.ref().update(batchUpdates);
        alert(`Success! Prize ₹${tournament.prizePool} credited to ${userData.username}`);
        return;
      }
      await db.ref(`tournaments/${tid}`).update(updates);
    } catch (err: any) { alert(err.message); }
  };

  const handleDelete = async (tid: string) => {
    if (window.confirm("Permanently delete this tournament?")) {
      await db.ref(`tournaments/${tid}`).remove();
    }
  };

  const selectedTourneyPlayers = viewPlayers ? tournaments.find(t => t.id === viewPlayers) : null;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm">
        <h2 className="text-xl font-black text-gray-800 uppercase tracking-tighter">Tournaments</h2>
        <button onClick={() => setShowForm(!showForm)} className="bg-indigo-600 text-white px-5 py-2 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-100 transition-all active:scale-95">
          {showForm ? 'CANCEL' : 'CREATE MATCH'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-indigo-600 p-6 rounded-[2.5rem] shadow-xl space-y-4 animate-in fade-in slide-in-from-top-4 duration-300">
          <h3 className="text-white text-xs font-black uppercase tracking-widest mb-2">New Match Setup</h3>
          <input type="text" placeholder="Tournament Name" className="w-full px-4 py-4 bg-white/10 rounded-2xl border border-white/20 text-white font-bold outline-none placeholder:text-white/40" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} required />
          <div className="flex gap-4">
            <input type="number" placeholder="Entry (₹)" className="flex-1 px-4 py-4 bg-white/10 rounded-2xl border border-white/20 text-white font-bold outline-none placeholder:text-white/40" value={formData.entryFee} onChange={e => setFormData({ ...formData, entryFee: parseFloat(e.target.value) })} required />
            <input type="number" placeholder="Prize (₹)" className="flex-1 px-4 py-4 bg-white/10 rounded-2xl border border-white/20 text-white font-bold outline-none placeholder:text-white/40" value={formData.prizePool} onChange={e => setFormData({ ...formData, prizePool: parseFloat(e.target.value) })} required />
          </div>
          <input type="datetime-local" className="w-full px-4 py-4 bg-white/10 rounded-2xl border border-white/20 text-white font-bold outline-none" value={formData.matchTime} onChange={e => setFormData({ ...formData, matchTime: e.target.value })} required />
          <button type="submit" className="w-full py-4 bg-white text-indigo-600 rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">PUBLISH TOURNAMENT</button>
        </form>
      )}

      {viewPlayers && selectedTourneyPlayers && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-8 relative max-h-[80vh] overflow-y-auto">
             <button onClick={() => setViewPlayers(null)} className="absolute top-6 right-6 text-gray-400"><i className="fas fa-times text-xl"></i></button>
             <h3 className="text-lg font-black mb-6 uppercase tracking-tighter">Players: {selectedTourneyPlayers.title}</h3>
             <div className="space-y-3">
                {Object.keys(selectedTourneyPlayers.participants || {}).length === 0 ? <p className="text-gray-400 text-center py-10 font-bold uppercase text-[10px]">No players yet.</p> : 
                 Object.entries(selectedTourneyPlayers.participants || {}).map(([uid, data]: [string, any]) => (
                   <div key={uid} className="bg-gray-50 p-4 rounded-2xl border border-gray-100 flex justify-between items-center">
                      <div>
                        <p class="text-[11px] font-black text-gray-900 uppercase">{data.gameUsername}</p>
                        <p class="text-[9px] text-indigo-600 font-black">UID: {data.gameUid}</p>
                      </div>
                      <div class="text-right">
                        <p class="text-[7px] text-gray-400 uppercase font-black">App ID</p>
                        <p class="text-[11px] font-black text-gray-600 bg-white px-2 py-1 rounded-lg border tracking-widest">{data.appId || '---'}</p>
                      </div>
                   </div>
                 ))}
             </div>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {tournaments.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200">
            <p className="text-gray-400 text-xs font-black uppercase">No tournaments found</p>
          </div>
        ) : (
          tournaments.reverse().map(t => (
            <div key={t.id} className="bg-white p-5 rounded-[2rem] shadow-sm border border-gray-100">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-black text-gray-900 uppercase tracking-tighter text-sm">{t.title}</h4>
                  <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{new Date(t.matchTime).toLocaleString()}</p>
                </div>
                <div className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase ${t.status === 'Live' ? 'bg-red-50 text-red-600' : t.status === 'Completed' ? 'bg-gray-100 text-gray-600' : 'bg-blue-50 text-blue-600'}`}>
                  {t.status}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 mt-4">
                <button onClick={() => updateStatus(t.id, 'Live')} disabled={t.status === 'Completed'} className="text-[9px] font-black py-2.5 bg-red-600 text-white rounded-xl disabled:opacity-30 uppercase active:scale-95 transition-all">GO LIVE</button>
                <button onClick={() => updateStatus(t.id, 'Completed')} disabled={t.status === 'Completed'} className="text-[9px] font-black py-2.5 bg-green-600 text-white rounded-xl disabled:opacity-30 uppercase active:scale-95 transition-all">PAY WINNER</button>
                <button onClick={() => setViewPlayers(t.id)} className="text-[9px] font-black py-2.5 bg-indigo-50 text-indigo-600 rounded-xl uppercase active:scale-95 transition-all">VIEW PLAYERS</button>
                <button onClick={() => handleDelete(t.id)} className="text-[9px] font-black py-2.5 bg-red-50 text-red-600 rounded-xl uppercase active:scale-95 transition-all">DELETE</button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

