        batchUpdates[`tournaments/${tid}/winnerUid`] = winnerUid;

        const txnRef = db.ref(`users/${winnerUid}/transactions`).push();
        batchUpdates[`users/${winnerUid}/transactions/${txnRef.key}`] = {
          amount: tournament.prizePool,
          type: 'credit',
          description: `Tournament Prize: ${tournament.title}`,
          timestamp: Date.now()
        };

        await db.ref().update(batchUpdates);
        alert(`Success! Prize ₹${tournament.prizePool} credited to ${userData.username}`);
        return;
      }
      await db.ref(`tournaments/${tid}`).update(updates);
    } catch (err: any) { alert(err.message); }
  };

