import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { WalletRequest, UserData } from '../../types';

const AdminRequests: React.FC = () => {
  const [requests, setRequests] = useState<WalletRequest[]>([]);
  const [activeTab, setActiveTab] = useState<'deposit' | 'withdraw'>('deposit');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  useEffect(() => {
    const depRef = db.ref('addMoneyRequests');
    const handleDeposits = (snap: any) => {
      const data = snap.val();
      const list = data ? Object.keys(data).map(key => ({ 
        ...data[key], 
        id: key, 
        type: 'deposit' as const 
      })) : [];
      setRequests(prev => [...prev.filter(r => r.type !== 'deposit'), ...list]);
    };
    depRef.on('value', handleDeposits);

    const withRef = db.ref('withdrawRequests');
    const handleWithdraws = (snap: any) => {
      const data = snap.val();
      const list = data ? Object.keys(data).map(key => ({ 
        ...data[key], 
        id: key, 
        type: 'withdraw' as const 
      })) : [];
      setRequests(prev => [...prev.filter(r => r.type !== 'withdraw'), ...list]);
    };
    withRef.on('value', handleWithdraws);

    return () => {
      depRef.off('value', handleDeposits);
      withRef.off('value', handleWithdraws);
    };
  }, []);

  const handleAction = async (req: WalletRequest, status: 'approved' | 'rejected') => {
    if (!window.confirm(`Are you sure you want to ${status.toUpperCase()} this ₹${req.amount} request?`)) return;

    setIsProcessing(req.id);
    try {
      const updates: any = {};
      const path = req.type === 'deposit' ? 'addMoneyRequests' : 'withdrawRequests';

      // Update request status
      updates[`${path}/${req.id}/status`] = status;

      if (status === 'approved') {
        const userRef = db.ref(`users/${req.uid}`);
        const userSnap = await userRef.once('value');
        const userData: UserData = userSnap.val();

        if (!userData) throw new Error("User data not found.");

        if (req.type === 'deposit') {
          updates[`users/${req.uid}/wallet_deposit`] = (userData.wallet_deposit || 0) + req.amount;
        } else {
          const currentWinnings = userData.wallet_winnings || 0;
          if (currentWinnings < req.amount) throw new Error("User has insufficient winnings balance.");
          updates[`users/${req.uid}/wallet_winnings`] = currentWinnings - req.amount;
        }

        // Add Transaction Record
        const txnRef = db.ref(`users/${req.uid}/transactions`).push();
        updates[`users/${req.uid}/transactions/${txnRef.key}`] = {
          amount: req.amount,
          type: req.type === 'deposit' ? 'credit' : 'debit',
          description: req.type === 'deposit' ? 'Wallet Deposit Approved' : 'Withdrawal Approved',
          timestamp: Date.now()
        };
      }

      await db.ref().update(updates);
      alert(`Request ${status} successfully!`);
    } catch (err: any) { 
      alert("Error: " + err.message); 
    } finally { 
      setIsProcessing(null); 
    }
  };

  const filtered = requests.filter(r => r.type === activeTab && r.status === 'pending');

  return (
    <div className="space-y-6">
      <div className="flex bg-white rounded-2xl p-1 shadow-sm border border-gray-100">
        <button 
          onClick={() => setActiveTab('deposit')} 
          className={`flex-1 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'deposit' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-400'}`}
        >
          Deposits
        </button>
        <button 
          onClick={() => setActiveTab('withdraw')} 
          className={`flex-1 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'withdraw' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-400'}`}
        >
          Withdraws
        </button>
      </div>

      <div className="space-y-4">
        {filtered.length === 0 ? (
          <div className="text-center py-24 bg-white rounded-[3rem] border border-dashed border-gray-200">
            <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
              <i className="fas fa-check-double text-2xl text-gray-300"></i>
            </div>
            <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">All caught up!</p>
          </div>
        ) : (
          filtered.map(req => (
            <div key={req.id} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <h4 className="font-black text-gray-900 uppercase tracking-tighter text-sm">{req.username}</h4>
                    <span className="bg-blue-600 text-white text-[9px] font-black px-2 py-0.5 rounded-lg tracking-widest">{(req as any).appId || '------'}</span>
                  </div>
                  <p className="text-[9px] text-gray-400 font-bold uppercase">{new Date(req.createdAt).toLocaleString()}</p>
                </div>
                <div className="text-right">
                  <p className="text-2xl font-black text-indigo-600">₹{req.amount}</p>
                  <p className="text-[7px] font-black text-gray-400 uppercase tracking-widest">Request Amount</p>
                </div>
              </div>

              <div className="bg-gray-50 rounded-2xl p-4 mb-5 border border-gray-100">
                <p className="text-[8px] text-gray-400 font-black uppercase mb-1">{req.type === 'deposit' ? 'Reference (Txn ID)' : 'Redeem To (UPI)'}</p>
                <p className="text-xs font-black text-gray-700 select-all break-all">
                  {req.type === 'deposit' ? req.txnId : req.upiId}
                </p>
              </div>

              <div className="flex gap-3">
                <button 
                  disabled={isProcessing === req.id}
                  onClick={() => handleAction(req, 'approved')} 
                  className="flex-1 py-4 bg-green-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-lg shadow-green-100 active:scale-95 disabled:opacity-50 transition-all"
                >
                  {isProcessing === req.id ? '...' : 'Approve'}
                </button>
                <button 
                  disabled={isProcessing === req.id}
                  onClick={() => handleAction(req, 'rejected')} 
                  className="flex-1 py-4 bg-red-50 text-red-600 rounded-2xl text-[10px] font-black uppercase active:scale-95 disabled:opacity-50 transition-all"
                >
                  Reject
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

