import React, { useState } from 'react';
import { auth, db } from '../firebase';
import { UserData } from '../types';

const LoginPage: React.FC = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [referralCode, setReferralCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const generateAppId = () => Math.floor(100000 + Math.random() * 900000).toString();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isLogin) {
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        const user = userCredential.user;
        if (user) {
          const userSnap = await db.ref(`users/${user.uid}`).once('value');
          const userData = userSnap.val();
          if (userData?.banUntil && userData.banUntil > Date.now()) {
            await auth.signOut();
            setError(`Banned until ${new Date(userData.banUntil).toLocaleString()}`);
            setLoading(false);
            return;
          }
        }
      } else {
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        const user = userCredential.user;
        if (user) {
          const appId = generateAppId();
          const role = email.includes('admin') ? 'admin' : 'user';

          const newUser: Partial<UserData> = {
            appId, username, email, role,
            wallet_deposit: 0, wallet_winnings: 0,
            totalKills: 0, totalWins: 0, matchesPlayed: 0, referralCount: 0,
            createdAt: Date.now()
          };

          if (referralCode && referralCode.length === 6) {
            const refQuery = await db.ref('users').orderByChild('appId').equalTo(referralCode).once('value');
            if (refQuery.exists()) {
              const refUid = Object.keys(refQuery.val())[0];
              const refData = refQuery.val()[refUid];

              // Give bonus to referrer
              await db.ref(`users/${refUid}`).update({
                wallet_deposit: (refData.wallet_deposit || 0) + 5,
                referralCount: (refData.referralCount || 0) + 1
              });

              const txRef = db.ref(`users/${refUid}/transactions`).push();
              await txRef.set({
                amount: 5, type: 'credit', description: 'Referral Bonus', timestamp: Date.now()
              });

              newUser.referredBy = referralCode;
            }
          }
          await db.ref(`users/${user.uid}`).set(newUser);
        }
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen max-w-md mx-auto bg-white p-8 flex flex-col justify-center">
      <div className="text-center mb-10">
        <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto shadow-xl mb-4">
          <i className="fas fa-gamepad text-white text-4xl"></i>
        </div>
        <h1 className="text-3xl font-black text-gray-900 uppercase italic tracking-tighter">Arena Pro</h1>
      </div>

      <div className="flex bg-gray-100 rounded-2xl p-1 mb-8">
        <button onClick={() => setIsLogin(true)} className={`flex-1 py-3 rounded-xl font-bold text-sm ${isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}>LOGIN</button>
        <button onClick={() => setIsLogin(false)} className={`flex-1 py-3 rounded-xl font-bold text-sm ${!isLogin ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500'}`}>SIGNUP</button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        {error && <div className="p-3 bg-red-50 text-red-600 text-xs rounded-xl border border-red-100">{error}</div>}
        {!isLogin && (
          <>
            <input type="text" placeholder="Username" className="w-full p-4 bg-gray-50 border rounded-2xl outline-none font-bold" value={username} onChange={e => setUsername(e.target.value)} required />
            <input type="text" placeholder="Referral Code (Optional)" className="w-full p-4 bg-gray-50 border rounded-2xl outline-none font-bold" value={referralCode} onChange={e => setReferralCode(e.target.value)} maxLength={6} />
          </>
        )}
        <input type="email" placeholder="Email Address" className="w-full p-4 bg-gray-50 border rounded-2xl outline-none font-bold" value={email} onChange={e => setEmail(e.target.value)} required />
        <input type="password" placeholder="Password" className="w-full p-4 bg-gray-50 border rounded-2xl outline-none font-bold" value={password} onChange={e => setPassword(e.target.value)} required />
        <button type="submit" disabled={loading} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase shadow-lg active:scale-95 disabled:opacity-50">
          {loading ? 'Entering...' : isLogin ? 'Enter Arena' : 'Join Arena'}
        </button>
      </form>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect, useRef } from 'react';
import { auth, db } from '../../firebase';
import { Tournament, UserData, GlobalChatMessage, PaymentProof } from '../../types';

const UserHome: React.FC = () => {
  const [userData, setUserData] = useState<UserData | null>(null);
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [chatMessages, setChatMessages] = useState<GlobalChatMessage[]>([]);
  const [proofs, setProofs] = useState<PaymentProof[]>([]);
  const [activeTab, setActiveTab] = useState<'matches' | 'chat' | 'feed'>('matches');
  const [chatText, setChatText] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const user = auth.currentUser;
    if (user) {
      db.ref(`users/${user.uid}`).on('value', s => setUserData(s.val()));
    }

    db.ref('tournaments').on('value', s => {
      const data = s.val() || {};
      setTournaments(Object.keys(data).map(key => ({ ...data[key], id: key })).filter(t => t.status !== 'Completed'));
    });

    db.ref('globalChat').limitToLast(50).on('value', s => {
      const data = s.val() || {};
      setChatMessages(Object.values(data));
    });

    db.ref('paymentProofs').on('value', s => {
      const data = s.val() || {};
      setProofs(Object.values(data).reverse());
    });

    return () => {
      db.ref(`users/${user?.uid}`).off();
      db.ref('tournaments').off();
      db.ref('globalChat').off();
      db.ref('paymentProofs').off();
    };
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, activeTab]);

  const sendChat = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatText.trim() || !userData) return;
    await db.ref('globalChat').push({
      senderId: userData.uid || auth.currentUser?.uid,
      senderName: userData.username,
      senderAppId: userData.appId,
      text: chatText.trim(),
      timestamp: Date.now(),
      role: 'user'
    });
    setChatText('');
  };

  const getRank = (kills: number) => {
    if (kills > 250) return { name: 'Heroic', color: 'text-red-500' };
    if (kills > 100) return { name: 'Platinum', color: 'text-blue-400' };
    if (kills > 50) return { name: 'Gold', color: 'text-yellow-500' };
    if (kills > 10) return { name: 'Silver', color: 'text-gray-400' };
    return { name: 'Bronze', color: 'text-amber-600' };
  };

  return (
    <div className="space-y-6">
      {/* Stats Bar */}
      <div className="grid grid-cols-3 gap-3">
        <div className="bg-white p-4 rounded-3xl shadow-sm border text-center">
          <p className="text-xl font-black text-gray-800">{userData?.totalKills || 0}</p>
          <p className="text-[8px] font-black uppercase text-gray-400">Total Kills</p>
        </div>
        <div className="bg-indigo-900 p-4 rounded-3xl shadow-lg text-center border-b-4 border-indigo-700">
          <p className={`text-xs font-black uppercase ${getRank(userData?.totalKills || 0).color}`}>
            {getRank(userData?.totalKills || 0).name}
          </p>
          <p className="text-[8px] font-black uppercase text-white/40">Your Rank</p>
        </div>
        <div className="bg-white p-4 rounded-3xl shadow-sm border text-center">
          <p className="text-xl font-black text-gray-800">{userData?.matchesPlayed || 0}</p>
          <p className="text-[8px] font-black uppercase text-gray-400">Matches</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white rounded-2xl p-1 shadow-sm border">
        <button onClick={() => setActiveTab('matches')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'matches' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Tourneys</button>
        <button onClick={() => setActiveTab('chat')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'chat' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Community</button>
        <button onClick={() => setActiveTab('feed')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'feed' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Feed</button>
      </div>

      <div className="animate-in fade-in duration-300">
        {activeTab === 'matches' && (
          <div className="space-y-4">
            {tournaments.map(t => (
              <div key={t.id} className="bg-white rounded-[2rem] overflow-hidden border shadow-sm">
                <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/400/180`} className="w-full h-32 object-cover" />
                <div className="p-5">
                  <div className="flex justify-between items-start mb-3">
                    <h4 className="font-black text-gray-900 uppercase tracking-tighter">{t.title}</h4>
                    <span className="bg-blue-50 text-blue-600 text-[8px] font-black px-2 py-0.5 rounded uppercase">{t.game}</span>
                  </div>
                  <div className="grid grid-cols-3 gap-2 mb-4 text-center">
                    <div className="bg-gray-50 p-2 rounded-xl"><p className="text-[7px] text-gray-400 font-black uppercase">Fee</p><p className="text-xs font-black">₹{t.entryFee}</p></div>
                    <div className="bg-green-50 p-2 rounded-xl"><p className="text-[7px] text-green-400 font-black uppercase">Prize</p><p className="text-xs font-black text-green-600">₹{t.prizePool}</p></div>
                    <div className="bg-indigo-50 p-2 rounded-xl"><p className="text-[7px] text-indigo-400 font-black uppercase">Kill</p><p className="text-xs font-black text-indigo-600">₹{t.perKillPrize || 0}</p></div>
                  </div>
                  <button className="w-full py-3 bg-blue-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg shadow-blue-100">JOIN NOW</button>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'chat' && (
          <div className="bg-white rounded-[2rem] border shadow-sm flex flex-col h-[400px]">
            <div className="flex-1 overflow-y-auto p-4 space-y-3 hide-scrollbar">
              {chatMessages.map((m, i) => (
                <div key={i} className={`flex flex-col ${m.senderId === auth.currentUser?.uid ? 'items-end' : 'items-start'}`}>
                  <p className="text-[8px] font-black text-gray-400 uppercase mb-0.5 ml-1">{m.senderName} ({m.senderAppId})</p>
                  <div className={`max-w-[80%] p-3 rounded-2xl text-[11px] font-bold ${m.senderId === auth.currentUser?.uid ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-gray-100 text-gray-800 rounded-tl-none'}`}>
                    {m.text}
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            <form onSubmit={sendChat} className="p-3 border-t flex gap-2">
              <input value={chatText} onChange={e => setChatText(e.target.value)} type="text" placeholder="Type something..." className="flex-1 bg-gray-50 border rounded-xl px-4 py-2 text-xs font-bold outline-none" />
              <button type="submit" className="w-10 h-10 bg-blue-600 text-white rounded-xl flex items-center justify-center shadow-lg"><i className="fas fa-paper-plane text-xs"></i></button>
            </form>
          </div>
        )}

        {activeTab === 'feed' && (
          <div className="grid grid-cols-2 gap-3">
            {proofs.map((p, i) => (
              <div key={i} className="bg-white p-2 rounded-2xl border shadow-sm">
                <img src={p.imageUrl} className="w-full h-24 object-cover rounded-xl mb-2" />
                <p className="text-[10px] font-black text-gray-800 truncate px-1">{p.winnerName}</p>
                <p className="text-[9px] font-black text-green-600 px-1">Received ₹{p.amount}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserHome;

import React, { useState, useEffect } from 'react';
