                <div className="bg-red-50 p-4 rounded-2xl border border-red-100 text-center">
                  <p className="text-[10px] font-black text-red-800 uppercase mb-1">Room ID</p>
                  <p className="text-xl font-black text-red-600 tracking-widest select-all">{t.roomId || 'PENDING'}</p>
                </div>
                <button onClick={() => copyAndPlay(t.roomId || '')} className="w-full py-3 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-100 flex items-center justify-center gap-2">
                  <i className="fas fa-play"></i> Copy & Play
                </button>
              </div>
            )}

            <div className="flex justify-between items-center text-[10px] font-black border-t pt-4">
              <span className="text-gray-400 uppercase">{new Date(t.matchTime).toLocaleString()}</span>
              {t.status !== 'Completed' && (
                <button onClick={() => submitResult(t.id)} className="text-blue-600 uppercase underline">Submit Screenshot</button>
              )}
            </div>
          </div>
        ))}
        {filtered.length === 0 && <div className="text-center py-20 text-gray-400 font-black uppercase text-xs">No matches found</div>}
      </div>
    </div>
  );
};

export default UserMyMatches;

import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { Tournament, UserData } from '../../types';

const AdminManageTournaments: React.FC = () => {
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [viewPlayers, setViewPlayers] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    title: '',
    game: 'Free Fire',
    entryFee: 0,
    prizePool: 0,
    perKillPrize: 0,
    matchTime: '',
    thumbnail: '',
  });

  useEffect(() => {
    const tourRef = db.ref('tournaments');
    const handleValue = (snapshot: any) => {
      const data = snapshot.val() || {};
      setTournaments(Object.keys(data).map(key => ({ ...data[key], id: key })));
    };
    tourRef.on('value', handleValue);
    return () => tourRef.off('value', handleValue);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const newRef = db.ref('tournaments').push();
    await newRef.set({ ...formData, status: 'Upcoming', participants: {}, createdAt: Date.now() });
    setShowForm(false);
    setFormData({ title: '', game: 'Free Fire', entryFee: 0, prizePool: 0, perKillPrize: 0, matchTime: '', thumbnail: '' });
  };

  const updateStatus = async (tid: string, status: string) => {
    if (status === 'Live') {
      const rid = window.prompt("Room ID:");
      const pass = window.prompt("Room Password:");
      if (!rid) return;
      await db.ref(`tournaments/${tid}`).update({ status, roomId: rid, roomPassword: pass });
    } else if (status === 'Completed') {
      const winnerId = window.prompt("Enter Winner's App ID:");
      if (!winnerId) return;

      const userQuery = await db.ref('users').orderByChild('appId').equalTo(winnerId).once('value');
      if (!userQuery.exists()) return alert("User not found!");
      const winnerUid = Object.keys(userQuery.val())[0];
      const winnerData = userQuery.val()[winnerUid];
      const tournament = tournaments.find(t => t.id === tid)!;

      // Handle payout logic
      const updates: any = {};
      updates[`users/${winnerUid}/wallet_winnings`] = (winnerData.wallet_winnings || 0) + tournament.prizePool;
      updates[`tournaments/${tid}/status`] = 'Completed';
      updates[`tournaments/${tid}/winnerUid`] = winnerUid;

      const txRef = db.ref(`users/${winnerUid}/transactions`).push();
      updates[`users/${winnerUid}/transactions/${txRef.key}`] = {
        amount: tournament.prizePool, type: 'credit', description: `Winner: ${tournament.title}`, timestamp: Date.now()
      };

      await db.ref().update(updates);
      alert("Payout Successful!");
    } else {
      await db.ref(`tournaments/${tid}`).update({ status });
    }
  };

  const selectedTournament = tournaments.find(t => t.id === viewPlayers);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl border shadow-sm">
        <h2 className="text-xl font-black uppercase tracking-tighter">Matches</h2>
        <button onClick={() => setShowForm(!showForm)} className="bg-indigo-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase">{showForm ? 'Close' : 'Create'}</button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-[2rem] border shadow-xl space-y-3 animate-in slide-in-from-top-4 duration-300">
          <input type="text" placeholder="Match Title" className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold outline-none" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} required />
          <div className="grid grid-cols-3 gap-2">
            <input type="number" placeholder="Fee" className="p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={formData.entryFee} onChange={e => setFormData({ ...formData, entryFee: parseFloat(e.target.value) })} required />
            <input type="number" placeholder="Pool" className="p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={formData.prizePool} onChange={e => setFormData({ ...formData, prizePool: parseFloat(e.target.value) })} required />
            <input type="number" placeholder="Per Kill" className="p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={formData.perKillPrize} onChange={e => setFormData({ ...formData, perKillPrize: parseFloat(e.target.value) })} required />
          </div>
          <input type="datetime-local" className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={formData.matchTime} onChange={e => setFormData({ ...formData, matchTime: e.target.value })} required />
          <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-lg">Publish Match</button>
        </form>
      )}

      <div className="space-y-4">
        {tournaments.reverse().map(t => (
          <div key={t.id} className="bg-white p-5 rounded-[2rem] border shadow-sm">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h4 className="font-black text-gray-900 uppercase tracking-tighter text-sm">{t.title}</h4>
                <p className="text-[9px] text-gray-400 font-bold uppercase">{new Date(t.matchTime).toLocaleString()}</p>
              </div>
              <span className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${t.status === 'Live' ? 'bg-red-50 text-red-600' : 'bg-gray-100 text-gray-500'}`}>{t.status}</span>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <button onClick={() => updateStatus(t.id, 'Live')} className="py-2.5 bg-red-600 text-white text-[9px] font-black rounded-xl uppercase">Go Live</button>
              <button onClick={() => updateStatus(t.id, 'Completed')} className="py-2.5 bg-green-600 text-white text-[9px] font-black rounded-xl uppercase">Pay Winner</button>
              <button onClick={() => setViewPlayers(t.id)} className="py-2.5 bg-indigo-50 text-indigo-600 text-[9px] font-black rounded-xl uppercase">Participants</button>
              <button onClick={() => db.ref(`tournaments/${t.id}`).remove()} className="py-2.5 bg-red-50 text-red-600 text-[9px] font-black rounded-xl uppercase">Delete</button>
            </div>
          </div>
        ))}
      </div>

      {viewPlayers && selectedTournament && (
        <div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-8 relative max-h-[80vh] overflow-y-auto">
             <button onClick={() => setViewPlayers(null)} className="absolute top-6 right-6 text-gray-400"><i className="fas fa-times"></i></button>
             <h3 className="text-lg font-black mb-6 uppercase tracking-tighter">Players: {selectedTournament.participants ? Object.keys(selectedTournament.participants).length : 0}</h3>
             <div className="space-y-3">
                {Object.entries(selectedTournament.participants || {}).map(([uid, p]: [string, any]) => (
                  <div key={uid} className="bg-gray-50 p-4 rounded-2xl border flex justify-between items-center">
                    <div>
                      <p className="text-[11px] font-black text-gray-900 uppercase">{p.gameUsername}</p>
                      <p className="text-[9px] text-indigo-600 font-black">ID: {p.appId}</p>
                      {p.resultScreenshot && <a href={p.resultScreenshot} target="_blank" className="text-[8px] text-blue-500 underline font-black uppercase mt-1 block">View Proof</a>}
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminManageTournaments;

import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { UserData } from '../../types';

const AdminDashboard: React.FC = () => {
  const [users, setUsers] = useState<UserData[]>([]);
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalPrize: 0,
    activeMatches: 0
  });

  useEffect(() => {
    db.ref('users').on('value', s => {
      const data = s.val() || {};
      const userList = Object.keys(data).map(key => ({ ...data[key], uid: key }));
      setUsers(userList);
      setStats(prev => ({ ...prev, totalUsers: userList.length }));
    });

    db.ref('tournaments').on('value', s => {
      const data = s.val() || {};
      const list = Object.values(data) as any[];
      setStats(prev => ({
        ...prev,
        activeMatches: list.filter(t => t.status !== 'Completed').length,
        totalPrize: list.filter(t => t.status === 'Completed').reduce((acc, curr) => acc + (curr.prizePool || 0), 0)
      }));
    });

    return () => {
      db.ref('users').off();
      db.ref('tournaments').off();
    };
  }, []);

  const banUser = async (uid: string, currentBan: boolean) => {
    if (currentBan) {
      await db.ref(`users/${uid}`).update({ banUntil: null, banReason: null });
    } else {
      const reason = window.prompt("Reason for ban:");
      if (!reason) return;
      await db.ref(`users/${uid}`).update({ 
        banUntil: Date.now() + (24 * 3600 * 1000 * 365), // 1 year
        banReason: reason 
      });
    }
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <p className="text-3xl font-black text-blue-600">{stats.totalUsers}</p>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Total Players</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <p className="text-3xl font-black text-green-600">₹{stats.totalPrize}</p>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Prize Paid</p>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] p-6 border shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-sm font-black uppercase tracking-tighter">Registered Users</h3>
          <span className="text-[9px] font-black bg-blue-50 text-blue-600 px-2 py-1 rounded uppercase">Real-time Feed</span>
        </div>
        <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 hide-scrollbar">
          {users.map(u => (
            <div key={u.uid} className="flex justify-between items-center bg-gray-50 p-4 rounded-2xl border border-gray-100">
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-0.5">
                  <p className="text-[11px] font-black text-gray-900 uppercase">{u.username}</p>
                  <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded tracking-widest">{u.appId}</span>
                </div>
                <p className="text-[8px] text-gray-400 font-bold uppercase">{u.email}</p>
                <div className="flex gap-3 mt-1 text-[9px] font-black text-blue-700 uppercase">
                  <span>D: ₹{u.wallet_deposit?.toFixed(0)}</span>
                  <span>W: ₹{u.wallet_winnings?.toFixed(0)}</span>
                </div>
              </div>
              <button onClick={() => banUser(u.uid, !!u.banUntil)} className={`text-[8px] font-black px-3 py-1.5 rounded-xl uppercase ${u.banUntil ? 'bg-green-100 text-green-600' : 'bg-red-50 text-red-600'}`}>
                {u.banUntil ? 'Unban' : 'Ban'}
              </button>
            </div>
          ))}
          {users.length === 0 && <p className="text-center text-gray-400 py-10 text-xs uppercase font-black">No users registered yet</p>}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
