  const [proofData, setProofData] = useState({ name: '', amount: 0, url: '' });

  useEffect(() => {
    db.ref('settings').on('value', s => {
      if (s.val()) setQrUrl(s.val().qrCodeUrl || '');
    });
  }, []);

  const updateQr = async () => {
    setLoading(true);
    await db.ref('settings').update({ qrCodeUrl: qrUrl });
