          <input type="number" placeholder="Amount (₹)" className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={proofData.amount} onChange={e => setProofData({...proofData, amount: parseFloat(e.target.value)})} required />
          <input type="text" placeholder="Screenshot URL" className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={proofData.url} onChange={e => setProofData({...proofData, url: e.target.value})} required />
