import React, { useState, useEffect, useRef } from 'react';
import { auth, db } from '../../firebase';
import { Tournament, UserData, GlobalChatMessage, PaymentProof } from '../../types';

const UserHome: React.FC = () => {
  const [userData, setUserData] = useState<UserData | null>(null);
  const [tournaments, setTournaments] = useState<Tournament[]>([]);
  const [chatMessages, setChatMessages] = useState<GlobalChatMessage[]>([]);
  const [proofs, setProofs] = useState<PaymentProof[]>([]);
  const [activeTab, setActiveTab] = useState<'matches' | 'chat' | 'feed'>('matches');
  const [chatText, setChatText] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const user = auth.currentUser;
    if (user) {
      db.ref(`users/${user.uid}`).on('value', s => setUserData(s.val()));
    }

    db.ref('tournaments').on('value', s => {
      const data = s.val() || {};
      // Fix: Map keys to 'id' and cast to Tournament[] to satisfy TypeScript requirements
      const tournamentList = Object.keys(data).map(key => ({ ...data[key], id: key })) as Tournament[];
      setTournaments(tournamentList.filter(t => t.status !== 'Completed'));
    });

    db.ref('globalChat').limitToLast(50).on('value', s => {
      const data = s.val() || {};
      setChatMessages(Object.values(data));
    });

    db.ref('paymentProofs').on('value', s => {
      const data = s.val() || {};
      // Fix: Map keys to 'id' property and cast to PaymentProof[] to resolve unknown[] type error on line 33
      const proofList = Object.keys(data).map(key => ({ ...data[key], id: key })) as PaymentProof[];
      setProofs(proofList.reverse());
    });

    return () => {
      db.ref(`users/${user?.uid}`).off();
      db.ref('tournaments').off();
      db.ref('globalChat').off();
      db.ref('paymentProofs').off();
    };
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, activeTab]);

  const sendChat = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatText.trim() || !userData) return;
    await db.ref('globalChat').push({
      senderId: userData.uid || auth.currentUser?.uid,
      senderName: userData.username,
      senderAppId: userData.appId,
      text: chatText.trim(),
      timestamp: Date.now(),
      role: 'user'
    });
    setChatText('');
  };

  const getRank = (kills: number) => {
    if (kills > 250) return { name: 'Heroic', color: 'text-red-500' };
    if (kills > 100) return { name: 'Platinum', color: 'text-blue-400' };
    if (kills > 50) return { name: 'Gold', color: 'text-yellow-500' };
    if (kills > 10) return { name: 'Silver', color: 'text-gray-400' };
    return { name: 'Bronze', color: 'text-amber-600' };
  };

  return (
    <div className="space-y-6">
      {/* Stats Bar */}
      <div className="grid grid-cols-3 gap-3">
        <div className="bg-white p-4 rounded-3xl shadow-sm border text-center">
          <p className="text-xl font-black text-gray-800">{userData?.totalKills || 0}</p>
          <p className="text-[8px] font-black uppercase text-gray-400">Total Kills</p>
        </div>
        <div className="bg-indigo-900 p-4 rounded-3xl shadow-lg text-center border-b-4 border-indigo-700">
          <p className={`text-xs font-black uppercase ${getRank(userData?.totalKills || 0).color}`}>
            {getRank(userData?.totalKills || 0).name}
          </p>
          <p className="text-[8px] font-black uppercase text-white/40">Your Rank</p>
        </div>
        <div className="bg-white p-4 rounded-3xl shadow-sm border text-center">
          <p className="text-xl font-black text-gray-800">{userData?.matchesPlayed || 0}</p>
          <p className="text-[8px] font-black uppercase text-gray-400">Matches</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white rounded-2xl p-1 shadow-sm border">
        <button onClick={() => setActiveTab('matches')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'matches' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Tourneys</button>
        <button onClick={() => setActiveTab('chat')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'chat' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Community</button>
        <button onClick={() => setActiveTab('feed')} className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'feed' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>Feed</button>
      </div>

      <div className="animate-in fade-in duration-300">
        {activeTab === 'matches' && (
          <div className="space-y-4">
            {tournaments.map(t => (
              <div key={t.id} className="bg-white rounded-[2rem] overflow-hidden border shadow-sm">
                <img src={t.thumbnail || `https://picsum.photos/seed/${t.id}/400/180`} className="w-full h-32 object-cover" />
                <div className="p-5">
                  <div className="flex justify-between items-start mb-3">
                    <h4 className="font-black text-gray-900 uppercase tracking-tighter">{t.title}</h4>
                    <span className="bg-blue-50 text-blue-600 text-[8px] font-black px-2 py-0.5 rounded uppercase">{t.game}</span>
                  </div>
                  <div className="grid grid-cols-3 gap-2 mb-4 text-center">
                    <div className="bg-gray-50 p-2 rounded-xl"><p className="text-[7px] text-gray-400 font-black uppercase">Fee</p><p className="text-xs font-black">₹{t.entryFee}</p></div>
                    <div className="bg-green-50 p-2 rounded-xl"><p className="text-[7px] text-green-400 font-black uppercase">Prize</p><p className="text-xs font-black text-green-600">₹{t.prizePool}</p></div>
                    <div className="bg-indigo-50 p-2 rounded-xl"><p className="text-[7px] text-indigo-400 font-black uppercase">Kill</p><p className="text-xs font-black text-indigo-600">₹{t.perKillPrize || 0}</p></div>
                  </div>
                  <button className="w-full py-3 bg-blue-600 text-white font-black rounded-xl text-[10px] uppercase shadow-lg shadow-blue-100">JOIN NOW</button>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'chat' && (
          <div className="bg-white rounded-[2rem] border shadow-sm flex flex-col h-[400px]">
            <div className="flex-1 overflow-y-auto p-4 space-y-3 hide-scrollbar">
              {chatMessages.map((m, i) => (
                <div key={i} className={`flex flex-col ${m.senderId === auth.currentUser?.uid ? 'items-end' : 'items-start'}`}>
                  <p className="text-[8px] font-black text-gray-400 uppercase mb-0.5 ml-1">{m.senderName} ({m.senderAppId})</p>
                  <div className={`max-w-[80%] p-3 rounded-2xl text-[11px] font-bold ${m.senderId === auth.currentUser?.uid ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-gray-100 text-gray-800 rounded-tl-none'}`}>
                    {m.text}
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            <form onSubmit={sendChat} className="p-3 border-t flex gap-2">
              <input value={chatText} onChange={e => setChatText(e.target.value)} type="text" placeholder="Type something..." className="flex-1 bg-gray-50 border rounded-xl px-4 py-2 text-xs font-bold outline-none" />
              <button type="submit" className="w-10 h-10 bg-blue-600 text-white rounded-xl flex items-center justify-center shadow-lg"><i className="fas fa-paper-plane text-xs"></i></button>
            </form>
          </div>
        )}

        {activeTab === 'feed' && (
          <div className="grid grid-cols-2 gap-3">
            {proofs.map((p, i) => (
              <div key={i} className="bg-white p-2 rounded-2xl border shadow-sm">
                <img src={p.imageUrl} className="w-full h-24 object-cover rounded-xl mb-2" />
                <p className="text-[10px] font-black text-gray-800 truncate px-1">{p.winnerName}</p>
                <p className="text-[9px] font-black text-green-600 px-1">Received ₹{p.amount}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserHome;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { auth, db } from '../../firebase';
import { UserData } from '../../types';

const UserProfile: React.FC = () => {
  const [userData, setUserData] = useState<UserData | null>(null);
  const navigate = useNavigate();

  useEffect(() => {
    const user = auth.currentUser;
    if (user) {
      const userRef = db.ref(`users/${user.uid}`);
      const handleValue = (snapshot: any) => {
        setUserData(snapshot.val());
      };
      userRef.on('value', handleValue);
      return () => userRef.off('value', handleValue);
    }
  }, []);

  const handleLogout = async () => {
    await auth.signOut();
  };

  const handleReset = async () => {
    if (auth.currentUser?.email) {
      await auth.sendPasswordResetEmail(auth.currentUser.email);
      alert("Password reset link sent to your email.");
    }
  };

  const getRank = (kills: number) => {
    if (kills > 250) return { name: 'Heroic', color: 'text-red-500', bg: 'bg-red-50' };
    if (kills > 100) return { name: 'Platinum', color: 'text-blue-500', bg: 'bg-blue-50' };
    if (kills > 50) return { name: 'Gold', color: 'text-yellow-600', bg: 'bg-yellow-50' };
    if (kills > 10) return { name: 'Silver', color: 'text-gray-500', bg: 'bg-gray-100' };
    return { name: 'Bronze', color: 'text-amber-700', bg: 'bg-amber-50' };
  };

  const matches = userData?.matchesPlayed || 0;
  const wins = userData?.totalWins || 0;
  const kills = userData?.totalKills || 0;

  const winRate = matches > 0 ? ((wins / matches) * 100).toFixed(1) : "0.0";
  const avgKills = matches > 0 ? (kills / matches).toFixed(1) : "0.0";
  const currentRank = getRank(kills);

  return (
    <div className="space-y-6 pb-6">
      {/* Header Profile Info */}
      <div className="flex flex-col items-center py-6 text-center">
        <div className="relative mb-4">
          <div className="w-24 h-24 rounded-full bg-gradient-to-tr from-blue-600 to-teal-400 p-1 shadow-xl">
            <div className="w-full h-full rounded-full bg-white flex items-center justify-center">
               <i className="fas fa-user-ninja text-4xl text-blue-600"></i>
            </div>
          </div>
          <div className={`absolute -bottom-1 -right-1 px-2 py-0.5 rounded-lg shadow-sm border border-white text-[8px] font-black uppercase ${currentRank.color} ${currentRank.bg}`}>
            {currentRank.name}
          </div>
        </div>
        <h2 className="text-2xl font-black text-gray-900">{userData?.username || 'Gamer'}</h2>
        <p className="text-xs text-gray-500 font-medium">{userData?.email}</p>
        <div className="mt-3 flex items-center gap-2 bg-blue-50 px-4 py-1.5 rounded-2xl border border-blue-100">
           <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Player ID:</span>
           <span className="text-sm font-black text-blue-700 select-all tracking-widest">{userData?.appId || '------'}</span>
        </div>
      </div>

      {/* Analytical Statistics Grid */}
      <div className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-sm font-black uppercase tracking-tighter text-gray-800">Combat Analytics</h3>
          <i className="fas fa-chart-line text-blue-500 opacity-20"></i>
        </div>

        <div className="grid grid-cols-3 gap-4">
          <div className="text-center">
            <div className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center mx-auto mb-2">
              <i className="fas fa-trophy text-sm"></i>
            </div>
            <p className="text-lg font-black text-gray-800">{winRate}%</p>
            <p className="text-[8px] font-black uppercase text-gray-400">Win Rate</p>
          </div>

          <div className="text-center">
            <div className="w-10 h-10 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-2">
              <i className="fas fa-crosshairs text-sm"></i>
            </div>
            <p className="text-lg font-black text-gray-800">{avgKills}</p>
            <p className="text-[8px] font-black uppercase text-gray-400">Kills/Match</p>
          </div>

          <div className="text-center">
            <div className="w-10 h-10 bg-green-50 text-green-500 rounded-2xl flex items-center justify-center mx-auto mb-2">
              <i className="fas fa-shield-alt text-sm"></i>
            </div>
            <p className="text-lg font-black text-gray-800">{matches}</p>
            <p className="text-[8px] font-black uppercase text-gray-400">Total Play</p>
          </div>
        </div>

        <div className="mt-6 pt-6 border-t border-gray-50 flex justify-around">
           <div className="text-center">
              <p className="text-xs font-black text-gray-700">{wins}</p>
              <p className="text-[7px] font-black text-gray-400 uppercase">Booyahs</p>
           </div>
           <div className="text-center">
              <p className="text-xs font-black text-gray-700">{kills}</p>
              <p className="text-[7px] font-black text-gray-400 uppercase">Eliminations</p>
           </div>
           <div className="text-center">
              <p className="text-xs font-black text-gray-700">{userData?.referralCount || 0}</p>
              <p className="text-[7px] font-black text-gray-400 uppercase">Referrals</p>
           </div>
        </div>
      </div>

      {/* Action Menu */}
      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        <button onClick={() => navigate('/support')} className="w-full p-5 border-b border-gray-50 flex items-center justify-between hover:bg-gray-50 transition-colors">
          <div className="flex items-center">
            <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center mr-4">
              <i className="fas fa-headset text-xs"></i>
            </div>
            <span className="text-sm font-bold text-gray-700 uppercase tracking-tighter">Support & Help</span>
          </div>
          <div className="bg-blue-600 text-white text-[9px] font-black px-2 py-0.5 rounded-full uppercase">Online</div>
