import React, { useState, useEffect } from 'react';
import { auth, db } from '../../firebase';
import { UserData, Transaction, AppSettings } from '../../types';

const UserWallet: React.FC = () => {
  const [userData, setUserData] = useState<UserData | null>(null);
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'add' | 'withdraw' | 'history'>('add');

  const [addAmount, setAddAmount] = useState('');
  const [txnId, setTxnId] = useState('');
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [upiId, setUpiId] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const user = auth.currentUser;
    if (user) {
      const userRef = db.ref(`users/${user.uid}`);
      userRef.on('value', (snapshot) => setUserData(snapshot.val()));

      const txRef = db.ref(`users/${user.uid}/transactions`);
      txRef.on('value', (snapshot) => {
        const data = snapshot.val();
        if (data) {
          const list = Object.keys(data).map(key => ({ ...data[key], id: key }));
          setTransactions(list.sort((a, b) => (b as any).timestamp - (a as any).timestamp));
        }
      });
    }

    const settingsRef = db.ref('settings');
    settingsRef.on('value', (snapshot) => setSettings(snapshot.val()));

    return () => {
      if (user) {
        db.ref(`users/${user.uid}`).off();
        db.ref(`users/${user.uid}/transactions`).off();
      }
      db.ref('settings').off();
    };
  }, []);

  const handleAddMoney = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!addAmount || !txnId || !userData) return;
    setLoading(true);

    try {
      const reqRef = db.ref('addMoneyRequests').push();
      await reqRef.set({
        uid: auth.currentUser?.uid,
        username: userData.username,
        appId: userData.appId, // Required for admin visibility
        amount: parseFloat(addAmount),
        txnId: txnId,
        status: 'pending',
        type: 'deposit',
        createdAt: Date.now()
      });
      alert("Deposit request submitted! Admin will verify your Txn ID.");
      setAddAmount('');
      setTxnId('');
      setActiveTab('history');
    } catch (err: any) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleWithdraw = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!withdrawAmount || !upiId || !userData) return;
    const amount = parseFloat(withdrawAmount);
    if (amount < 100) return alert("Minimum withdrawal is ₹100");
    if (amount > (userData.wallet_winnings || 0)) return alert("Insufficient winnings balance!");

    setLoading(true);
    try {
      const reqRef = db.ref('withdrawRequests').push();
      await reqRef.set({
        uid: auth.currentUser?.uid,
        username: userData.username,
        appId: userData.appId, // Required for admin visibility
        amount: amount,
        upiId: upiId,
        status: 'pending',
        type: 'withdraw',
        createdAt: Date.now()
      });
      alert("Withdraw request submitted successfully!");
      setWithdrawAmount('');
      setUpiId('');
      setActiveTab('history');
    } catch (err: any) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const totalBalance = (userData?.wallet_deposit || 0) + (userData?.wallet_winnings || 0);

  return (
    <div className="space-y-6 pb-6 animate-in fade-in duration-500">
      <div className="bg-gradient-to-br from-indigo-700 to-blue-500 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <i className="fas fa-wallet text-9xl -rotate-12"></i>
        </div>
        <div className="relative z-10">
          <p className="text-white/70 text-xs font-black uppercase tracking-widest mb-1">Current Balance</p>
          <h2 className="text-5xl font-black mb-8">₹{totalBalance.toFixed(2)}</h2>
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white/10 rounded-2xl p-4 backdrop-blur-md border border-white/20">
              <p className="text-[10px] text-white/50 uppercase font-black mb-1">Deposit</p>
              <p className="text-xl font-bold">₹{(userData?.wallet_deposit || 0).toFixed(2)}</p>
            </div>
            <div className="bg-white/10 rounded-2xl p-4 backdrop-blur-md border border-white/20">
              <p className="text-[10px] text-white/50 uppercase font-black mb-1">Winnings</p>
              <p className="text-xl font-bold text-green-300">₹{(userData?.wallet_winnings || 0).toFixed(2)}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex bg-white rounded-2xl p-1 shadow-sm border border-gray-100">
        <button onClick={() => setActiveTab('add')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400'}`}>Add Funds</button>
        <button onClick={() => setActiveTab('withdraw')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'withdraw' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400'}`}>Withdraw</button>
        <button onClick={() => setActiveTab('history')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'history' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400'}`}>History</button>
      </div>

      <div className="mt-4">
        {activeTab === 'add' && (
          <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 space-y-6">
            <div className="text-center">
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4">Scan QR to pay</p>
              <div className="bg-gray-50 p-4 rounded-[2rem] border-4 border-dashed border-gray-100 inline-block mb-6">
                <img 
                  src={settings?.qrCodeUrl || "https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=PAY_ARENA_PRO"} 
                  className="w-44 h-44 mx-auto rounded-xl"
                  alt="Payment QR"
                />
              </div>
            </div>
            <form onSubmit={handleAddMoney} className="space-y-4">
              <input type="number" required value={addAmount} onChange={e => setAddAmount(e.target.value)} placeholder="Amount (₹)" className="w-full px-5 py-4 bg-gray-50 border rounded-2xl font-bold outline-none focus:ring-2 focus:ring-blue-500" />
              <input type="text" required value={txnId} onChange={e => setTxnId(e.target.value)} placeholder="UTR / Transaction ID" className="w-full px-5 py-4 bg-gray-50 border rounded-2xl font-bold outline-none focus:ring-2 focus:ring-blue-500" />
              <button type="submit" disabled={loading} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl active:scale-95 disabled:opacity-50">Submit Payment</button>
            </form>
          </div>
        )}

        {activeTab === 'withdraw' && (
          <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-100 space-y-6">
            <div className="bg-yellow-50 p-4 rounded-2xl border border-yellow-100 flex items-center gap-3">
              <i className="fas fa-info-circle text-yellow-600"></i>
              <p className="text-[10px] font-bold text-yellow-800 uppercase">Minimum withdrawal amount is ₹100 from Winnings.</p>
            </div>
            <form onSubmit={handleWithdraw} className="space-y-4">
              <input type="number" required value={withdrawAmount} onChange={e => setWithdrawAmount(e.target.value)} placeholder="Redeem Amount (₹)" className="w-full px-5 py-4 bg-gray-50 border rounded-2xl font-bold outline-none focus:ring-2 focus:ring-blue-500" />
              <input type="text" required value={upiId} onChange={e => setUpiId(e.target.value)} placeholder="UPI ID (e.g. name@paytm)" className="w-full px-5 py-4 bg-gray-50 border rounded-2xl font-bold outline-none focus:ring-2 focus:ring-blue-500" />
              <button type="submit" disabled={loading} className="w-full py-5 bg-gray-900 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl active:scale-95 disabled:opacity-50">Request Payout</button>
            </form>
          </div>
        )}

        {activeTab === 'history' && (
          <div className="space-y-3">
            {transactions.map(tx => (
              <div key={tx.id} className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${tx.type === 'credit' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                    <i className={`fas ${tx.type === 'credit' ? 'fa-arrow-down' : 'fa-arrow-up'}`}></i>
                  </div>
                  <div>
                    <h4 className="font-black text-gray-800 text-[11px] uppercase truncate max-w-[120px]">{tx.description}</h4>
                    <p className="text-[8px] text-gray-400 font-bold uppercase">{new Date(tx.timestamp).toLocaleString()}</p>
                  </div>
                </div>
                <p className={`font-black text-sm ${tx.type === 'credit' ? 'text-green-600' : 'text-red-600'}`}>
                  {tx.type === 'credit' ? '+' : '-'} ₹{tx.amount.toFixed(0)}
                </p>
              </div>
            ))}
            {transactions.length === 0 && <p className="text-center py-10 text-gray-300 font-black uppercase text-xs">No transactions yet</p>}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserWallet;

import React, { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { WalletRequest, UserData } from '../../types';

const AdminRequests: React.FC = () => {
  const [requests, setRequests] = useState<WalletRequest[]>([]);
  const [activeTab, setActiveTab] = useState<'deposit' | 'withdraw'>('deposit');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

  useEffect(() => {
    // Single consolidated state to prevent race conditions
    const localState: { deposits: WalletRequest[], withdraws: WalletRequest[] } = { deposits: [], withdraws: [] };

    const updateRequests = () => {
      const all = [...localState.deposits, ...localState.withdraws];
      setRequests(all.sort((a, b) => b.createdAt - a.createdAt));
    };

    const depRef = db.ref('addMoneyRequests');
    const handleDeposits = (snap: any) => {
      const data = snap.val();
      localState.deposits = data ? Object.keys(data).map(key => ({ 
        ...data[key], 
        id: key, 
        type: 'deposit' as const 
      })) : [];
      updateRequests();
    };

    const withRef = db.ref('withdrawRequests');
    const handleWithdraws = (snap: any) => {
      const data = snap.val();
      localState.withdraws = data ? Object.keys(data).map(key => ({ 
        ...data[key], 
        id: key, 
        type: 'withdraw' as const 
      })) : [];
      updateRequests();
    };

    depRef.on('value', handleDeposits);
    withRef.on('value', handleWithdraws);

    return () => {
      depRef.off('value', handleDeposits);
      withRef.off('value', handleWithdraws);
    };
  }, []);

  const handleAction = async (req: WalletRequest, status: 'approved' | 'rejected') => {
    if (!window.confirm(`Are you sure you want to ${status.toUpperCase()} this request for ₹${req.amount}?`)) return;

    setIsProcessing(req.id);
    try {
      const updates: any = {};
      const path = req.type === 'deposit' ? 'addMoneyRequests' : 'withdrawRequests';
      updates[`${path}/${req.id}/status`] = status;

      if (status === 'approved') {
        const userSnap = await db.ref(`users/${req.uid}`).once('value');
        const userData: UserData = userSnap.val();
        if (!userData) throw new Error("Target user account no longer exists.");

        if (req.type === 'deposit') {
          updates[`users/${req.uid}/wallet_deposit`] = (userData.wallet_deposit || 0) + req.amount;
        } else {
          if ((userData.wallet_winnings || 0) < req.amount) throw new Error("User spent their winnings before approval.");
          updates[`users/${req.uid}/wallet_winnings`] = userData.wallet_winnings - req.amount;
        }

        const txnRef = db.ref(`users/${req.uid}/transactions`).push();
        updates[`users/${req.uid}/transactions/${txnRef.key}`] = {
          amount: req.amount,
          type: req.type === 'deposit' ? 'credit' : 'debit',
          description: req.type === 'deposit' ? 'Deposit Approved' : 'Withdrawal Approved',
          timestamp: Date.now()
        };
      }

      await db.ref().update(updates);
      alert(`Successfully ${status}!`);
    } catch (err: any) {
      alert("System Error: " + err.message);
    } finally {
      setIsProcessing(null);
    }
  };

  const filtered = requests.filter(r => r.type === activeTab && r.status === 'pending');

  return (
    <div className="space-y-6">
      <div className="flex bg-white rounded-2xl p-1 shadow-sm border">
        <button onClick={() => setActiveTab('deposit')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'deposit' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-400'}`}>Deposits</button>
        <button onClick={() => setActiveTab('withdraw')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${activeTab === 'withdraw' ? 'bg-indigo-600 text-white shadow-lg' : 'text-gray-400'}`}>Redeems</button>
      </div>

      <div className="space-y-4">
        {filtered.map(req => (
          <div key={req.id} className="bg-white p-6 rounded-[2.5rem] border shadow-sm animate-in slide-in-from-bottom-4 duration-300">
            <div className="flex justify-between items-start mb-4">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <h4 className="text-sm font-black uppercase tracking-tighter text-gray-900">{req.username}</h4>
                  <span className="bg-indigo-600 text-white text-[8px] font-black px-2 py-0.5 rounded-lg tracking-widest">{req.appId || 'NEW'}</span>
                </div>
                <p className="text-[9px] text-gray-400 font-bold uppercase">{new Date(req.createdAt).toLocaleString()}</p>
              </div>
              <div className="text-right">
                <p className="text-2xl font-black text-indigo-600">₹{req.amount}</p>
              </div>
            </div>

            <div className="bg-gray-50 rounded-2xl p-4 border mb-6">
              <p className="text-[7px] font-black text-gray-400 uppercase tracking-widest mb-1">{req.type === 'deposit' ? 'Txn Reference' : 'UPI Destination'}</p>
              <p className="text-xs font-black text-gray-800 break-all select-all">{req.type === 'deposit' ? req.txnId : req.upiId}</p>
            </div>

            <div className="flex gap-3">
              <button disabled={!!isProcessing} onClick={() => handleAction(req, 'approved')} className="flex-1 py-4 bg-green-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-lg shadow-green-100 disabled:opacity-50">Approve</button>
              <button disabled={!!isProcessing} onClick={() => handleAction(req, 'rejected')} className="flex-1 py-4 bg-red-50 text-red-600 rounded-2xl text-[10px] font-black uppercase disabled:opacity-50">Reject</button>
            </div>
          </div>
        ))}
        {filtered.length === 0 && <div className="text-center py-20 text-gray-300 font-black uppercase text-xs">No pending requests</div>}
      </div>
    </div>
  );
};

export default AdminRequests;

